window.ASBAB_NUZUL_CACHE["59"] = {"asbab_nuzul":{"5":[{"ar":"عَنِ ابْنِ عُمَرَ رضي الله عنهما قَالَ: حَرَّقَ رَسُولُ اللهِ ﷺ نَخْلَ بَنِي النَّضِيرِ، وَقَطَعَ، وَهِيَ الْبُوَيْرَةُ، فَنَزَلَتْ: { مَا قَطَعْتُم مِّن لِّينَةٍ أَوْ تَرَكْتُمُوهَا قَآئِمَةً عَلَىٰٓ أُصُولِهَا فَبِإِذْنِ ٱللَّهِ }. واللفظ للبخاري.","id":""},{"ar":"عَنِ ابْنِ عُمَرَ رضي الله عنهما أَنَّ رَسُولَ اللهِ ﷺ قَطَعَ نَخْلَ بَنِي النَّضِيرِ، وَحَرَّقَ، وَلَهَا يَقُولُ حَسَّانُ:\nوَهَانَ عَلَى سَرَاةِ بَنِي لُؤَيِّ      حَرِيقٌ بِالْبُوَيْرَةِ مُسْتَطِيرُ\nوَفِي ذَلِكَ نَزَلَتْ { مَا قَطَعْتُم مِّن لِّينَةٍ أَوْ تَرَكْتُمُوهَا قَآئِمَةً عَلَىٰٓ أُصُولِهَا } الآيَة. واللفظ لمسلم.","id":""},{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما فِي قَوْلِ اللهِ عز و جل: { مَا قَطَعْتُم مِّن لِّينَةٍ أَوْ تَرَكْتُمُوهَا قَآئِمَةً عَلَىٰٓ أُصُولِهَا } قَالَ: اللِّينَةُ النَّخْلَةُ { وَلِيُخْزِىَ ٱلْفَـٰسِقِينَ }، قَالَ: اسْتَنْزَلُوهُمْ مِنْ حُصُونِهِمْ، قَالَ: وَأُمِرُوا بِقَطْعِ النَّخْلِ، فَحَكَّ فِي صُدُورِهِمْ، فَقَالَ الْمسْلِمُونَ: قَدْ قَطَعْنَا بَعْضاً وَتَرَكْنَا بَعْضاً، فَلَنَسْأَلَنَّ رَسُولَ اللهِ ﷺ: هَلْ لَنَا فِيمَا قَطَعْنَا مِنْ أَجْرٍ، وَهَلْ عَلَيْنَا فِيمَا تَرَكْنَا مِنْ وِزْرٍ، فَأَنْزَلَ اللهُ تَعَالَى: { مَا قَطَعْتُم مِّن لِّينَةٍ أَوْ تَرَكْتُمُوهَا قَآئِمَةً عَلَىٰٓ أُصُولِهَا } الآية. واللفظ للترمذي.","id":""}],"9":[{"ar":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه: أَنَّ رَجُلًا أَتَى النَّبِيَّ ﷺ، فَبَعَثَ إِلَى نِسَائِهِ، فَقُلْنَ: مَا مَعَنَا إِلَّا الْمَاءُ، فَقَالَ رَسُولُ اللهِ ﷺ: « مَنْ يَضُمُّ - أَوْ يُضِيفُ - هَذَا؟ » فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ: أَنَا، فَانْطَلَقَ بِهِ إِلَى امْرَأَتِهِ، فَقَالَ: أَكْرِمِي ضَيْفَ رَسُولِ اللهِ ﷺ، فَقَالَتْ: مَا عِنْدَنَا إِلَّا قُوتُ صِبْيَانِي، فَقَالَ: هَيِّئِي طَعَامَكِ، وَأَصْبِحِي سِرَاجَكِ، وَنَوِّمِي صِبْيَانَكِ، إِذَا أَرَادُوا عَشَاءً، فَهَيَّأَتْ طَعَامَهَا، وَأَصْبَحَتْ سِرَاجَهَا، وَنَوَّمَتْ صِبْيَانَهَا، ثُمَّ قَامَتْ كَأَنَّهَا تُصْلِحُ سِرَاجَهَا فَأَطْفَأَتْهُ، فَجَعَلَا يُرِيَانِهِ أَنَّهُمَا يَأْكُلَانِ، فَبَاتَا طَاوِيَيْنِ، فَلَمَّا أَصْبَحَ غَدَا إِلَى رَسُولِ اللهِ ﷺ فَقَالَ: « ضَحِكَ اللهُ اللَّيْلَةَ، أَوْ عَجِبَ مِنْ فَعَالِكُمَا » فَأَنْزَلَ اللهُ: { وَيُؤْثِرُونَ عَلَىٰٓ أَنفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ ۚ وَمَن يُوقَ شُحَّ نَفْسِهِۦ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ }. واللفظ للبخاري.","id":""}]},"mapping_ayat":{"59:1":[{"p":"Bukhari","n":5898,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ ذَكَرَ لِيمِنْ حَدِيثِهِ ذَلِكَ فَانْطَلَقْتُ حَتَّى دَخَلْتُ عَلَيْهِ فَسَأَلْتُهُ فَقَالَ انْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى عُمَرَ فَأَتَاهُ حَاجِبُهُ يَرْفَأُ فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ قَالَ نَعَمْ فَأَذِنَ لَهُمْ ثُمَّ قَالَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ قَالَ نَعَمْ قَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا قَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُ فَقَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَ قَالَا قَدْ قَالَ ذَلِكَ قَالَ عُمَرُ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ قَدْ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْفَيْءِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ فَقَالَ عَزَّ وَجَلَّ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ لَقَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ مِنْ هَذَا الْمَالِ نَفَقَةَ سَنَتِهِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ بِذَاكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ فَتَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهَا فَعَمِلَ بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ وَلِيِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضْتُهَا سَنَتَيْنِ أَعْمَلُ فِيهَا مَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ ثُمَّ جِئْتُمَانِي وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا جَمِيعٌ جِئْتَنِي تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكَ وَأَتَانِي هَذَا يَسْأَلُنِي نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ إِنْ شِئْتُمَا دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ فَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا فَادْفَعَاهَا إِلَيَّ فَأَنَا أَكْفِيكُمَاهَا","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] mengatakan, telah mengabarkan kepadaku [Malik bin Aus bin Al Hadatsan] dan [Muhammad bin Jubair bin Muth'im] menyebutkan kepadaku diantara haditsnya; 'maka aku berangkat hingga menemuinya dan bertanya kepadanya, dia menjawab; 'Aku berangkat hingga aku menemui [Umar]. Umar lantas ditemui oleh pengawal rumahnya dan mengucapkan selamat datang, kemudian ia bertanya; 'Apakah anda berkenan memberi izin untuk [Utsman], [Abdurrahman], [Zubai] r, dan [Sa'dari] ' 'Tentu' jawabnya. Penjaga itu pun mengizinkan mereka. kemudian dia bertanya lagi; 'apakah anda memberi izin kepada [Ali] dan [Abbas] ' 'ya' Jawab Umar. Abbas kemudian berkata; 'Wahai amirul mukminin, putuskanlah antara aku dan orang ini! ' Umar menjawab; 'Saya bersumpah kepada kalian dengan nama Allah yang karena- izin-Nya langit dan bumi tegak, bukankah kalian telah tahu bahwa Rasulullah Shallallahu'alaihi wa sallam telah bersabda: \"Kami tidak diwarisian, dan apa yang kami tinggalkan adalah sedekah!\" yang Rasulullah maksudkan adalah beliau sendiri.' Sekumpulan sahabat berkata; 'Nabi pernah mengatakan yang demikian.' Umar kemudian menemui Ali dan Abbas dan bertanya; 'bukankah kalian berdua tahu bahwa Rasulullah Shallallahu'alaihiwasallam telah menyabdakan yang demikian? ' Keduanya menjawab; 'Betul, Beliau telah bersabda sedemikian itu.' Umar berkata; 'sekarang saya akan menceritakan kepada kalian tentang persoalan ini, sesungguhnya Allah telah memberi pemberian special kepada Rasul-Nya Shallallahu'alaihiwasallam tentang harta fai` ini, dengan sesuatu yang tidak diberikan-Nya kepada seorang pun selainnya. Allah berfirman: 'Apa saja yang Allah berikan kepada Rasul-Nya…hingga firman-Nya Sesungguhnya Allah Maha Berkuasa. (QS. Alhasyr 1). Karenanya harta fai` tersebut adalah murni untuk Rasulullah Shallallahu'alaihiwasallam, demi Allah beliau tidak memberikannya secara special untuk kalian dan tidak pula mengutamakannya untuk kalian, sesungguhnya beliau juga telah memberikan harta itu kepada kalian dan meratakannya kepada kalian hingga tersisa dari harta ini, selanjutnya Nabi pergunakan harta itu untuk menafkahi keluarganya selama setahun, beliau mengambil harta sisanya dan beliau salurkan untuk harta Allah. Begitulah Rasulullah Shallallahu'alaihiwasallam memperlakukan harta itu semasa hidupnya. Saya bersumpah kepada kalian atas nama Allah, Bukankah kalian tahu terhadap itu semua? ' Mereka menjawab; 'Iya'. Kemudian Umar mengatakan secara khusus kepada Ali dan Abbas; 'Saya bersumpah kepada kalian berdua atas nama Allah, bukankah kalian berdua tahu itu semua? ' Keduanya menjawab; 'Benar'. Umar melanjutkan; 'Kemudian Allah mewafatkan Nabi-NYA Shallallahu'alaihiwasallam, lantas Abu Bakar berkata; 'Aku adalah wali Rasulullah Shallallahu'alaihiwasallam, ' dan dia memegang harta itu kemudian mengelola sebagaimana Rasulullah Shallallahu'alaihiwasallam mengelola, kemudian Allah mewafatkan Abu Bakar, sehingga aku katakan; 'Aku adalah wali dari walinya Rasulullah Shallallahu'alaihiwasallam, sehingga aku pegang harta itu selama dua tahun dan aku kelola sebagaimana Rasulullah Shallallahu'alaihiwasallam dan Abu Bakar mengelolanya, kemudian kalian berdua mendatangiku sedang ucapan kalian satu, dan perkara kalian berdua sepakat persis, kalian mendatangiku dengan harapan memintaku bagianmu lewat lajur keponakanmu, sedang orang ini memintaku bagian isterinya lewat lajur ayahnya, maka kutegaskan; Jika kalian berkenan, tanah itu akan kuserahkan kepada kalian berdua, sehingga kalian berdua memperoleh keputusan selain itu dariku, demi Allah yang atas seizin-Nya bumi dan langit menjadi tegak, Saya tak akan menetapkan keputusan selain itu hingga kiamat tiba, kalaulah kalian berdua merasa tidak mampu, serahkan padaku, saya akan mengelola harta itu sebagai ganti kalian.'"}],"59:3":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"59:5":[{"p":"Bukhari","n":3528,"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَحَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَنَزَلَتْ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Al Laits] dari [An Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah membakar kebun kurma Bani Nadlir dan memotongnya, yaitu yang ada di Buwairah. Kemudian turunlah ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya. Maka (semua itu) adalah dengan izin Allah) ' (Qs. Al Hasyr: 5)."},{"p":"Bukhari","n":4200,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ تَعَالَى{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }","trj":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, bahwasanya Rasulullah shallallahu 'alaihi wasallam membakar pepohonan kurma Bani Nadlir dan juga memotongnya, yakni Al Buwairah, maka Allah Ta'ala pun menurunkan ayat, \"Pepohonan (kurma) yang telah kalian tebang atau yang kalian biarkan berdiri tegak di atas pokoknya adalah atas dasar izin dari Allah, dan untuk menghinakan orang-orang yang fasik.\" (QS. Alhasyr 5)."},{"p":"Ibnu Majah","n":2799,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً }الْآيَةَ الْآيَةَ","trj":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah menberitakan kepada kami [Al Laits bin Sa'ad] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam membakar pohon kurma bani Nadlir dan menebasnya, yaitu kawasan Buwairah, kemudian Allah Subhanahu Wa Ta'ala menurunkan ayat: 'Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya (Qs. Al Hasyr 99: 5).'\""},{"p":"Muslim","n":3051,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَمُحَمَّدُ بْنُ رُمْحٍ قَالَا أَخْبَرَنَا اللَّيْثُ و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ زَادَ قُتَيْبَةُ وَابْنُ رُمْحٍ فِي حَدِيثِهِمَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Muhammad bin Rumh] keduanya berkata; telah mengabarkan kepada kami [Al Laits] dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah membakar dan menebang kebun kurma milik (Yahudi) Bani Nadlir di Buwairah, lalu Allah Azza Wa Jalla menurunkan ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya, maka (semua itu) adalah dengan izin Allah; dan Karena dia hendak memberikan kehinaan kepada orang-orang fasik) ' (Qs. Al Hasyr: 5)."},{"p":"Muslim","n":3052,"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ نَخْلَ بَنِي النَّضِيرِ وَحَرَّقَ وَلَهَا يَقُولُ حَسَّانُ وَهَانَ عَلَى سَرَاةِ بَنِي لُؤَيٍّحَرِيقٌ بِالْبُوَيْرَةِ مُسْتَطِيرُوَفِي ذَلِكَ نَزَلَتْ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا }الْآيَةَ","trj":"Telah menceritakan kepada kami [Sa'id bin Manshur] dan [Hannad bin As Sarry] keduanya berkata; telah menceritakan kepada kami [Ibnu Mubarak] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam pernah menebang dan membakar kebun kurma milik (Yahudi) Bani Nadlir, dalam peristiwa itu, Hassan sempat membaca sebait sya'ir: \"Alangkah terhinanya tokoh-tokoh Bani Lu`aiy saat kebakaran melumat kebun kurma mereka yang berada di daerah Buwairah.\" Sehubungan dengan itu, maka turunlah ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya...) ' (Qs. Al Hasyr: 5)."},{"p":"Tirmidzi","n":1472,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذَهَبَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ إِلَى هَذَا وَلَمْ يَرَوْا بَأْسًا بِقَطْعِ الْأَشْجَارِ وَتَخْرِيبِ الْحُصُونِ وَكَرِهَ بَعْضُهُمْ ذَلِكَ وَهُوَ قَوْلُ الْأَوْزَاعِيِّ قَالَ الْأَوْزَاعِيُّ وَنَهَى أَبُو بَكْرٍ الصِّدِّيقُ أَنْ يَقْطَعَ شَجَرًا مُثْمِرًا أَوْ يُخَرِّبَ عَامِرًا وَعَمِلَ بِذَلِكَ الْمُسْلِمُونَ بَعْدَهُ و قَالَ الشَّافِعِيُّ لَا بَأْسَ بِالتَّحْرِيقِ فِي أَرْضِ الْعَدُوِّ وَقَطْعِ الْأَشْجَارِ وَالثِّمَارِ و قَالَ أَحْمَدُ وَقَدْ تَكُونُ فِي مَوَاضِعَ لَا يَجِدُونَ مِنْهُ بُدًّا فَأَمَّا بِالْعَبَثِ فَلَا تُحَرَّقْ و قَالَ إِسْحَقُ التَّحْرِيقُ سُنَّةٌ إِذَا كَانَ أَنْكَى فِيهِمْ","trj":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] berkata, \"bahwasanya Rasulullah shallallahu 'alaihi wasallam menebang dan membakar kebun kurma milik bani Nadhir, tepatnya di wilayah Buwairah. Maka Allah menurunkan ayat-Nya: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya, maka (semua itu) adalah dengan izin Allah; dan karena Dia hendak memberikan kehinaan kepada orang-orang fasik) ' -Qs. Al Hasyr: 5-Dalam bab ini ada hadits serupa dari Ibnu Abbas. Hadits ini derajatnya hasan shahih. sebagian ulama` berpegangan dengan hadits ini, dan mereka tidak mempermasalahkan atas pembolehan menebang pohon kurma dan menghancurkan benteng. Namun sebagian yang lain memakruhkan hal tersebut, dan ini adalah pendapat Al Auza'i. Al Auza'I berkata, \"Abu Bakar Ash Shiddiq telah melarang menebang pohon yang sedang berbuah atau menghancurkan bangunan, dan kaum muslimin setelahnya juga melakukan sebagaimana yang dilakukan oleh Abu Bakar Ash Shiddiq.\" Imam Syafi'I berkata, \"Tidak apa-apa membakar dan menebang pohon yang berbuah di wilayah musuh.\" Imam Ahmad berkata, \"Untuk beberapa kasus tidak apa-apa melakukan hal itu, tetapi jika itu menimbulkan kesia-siaan maka tidak boleh membakar.\" Sementara Ishaq mengatakan, \"Jika membakar itu bisa membuat kerugian dipihak musuh maka itu sunah.\""},{"p":"Tirmidzi","n":3053,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَحَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَخْلَ بَنِي النَّضِيرِ وَقَطَّعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar radliallahu 'anhuma], ia berkata; Rasulullah shallallahu 'alaihi wasallam membakar pohon kurma Bani An Nazhir, dan menebanginya dan pohon tersebut ada di Al Buwairah. Kemudian Allah menurunkan ayat: \"Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya, maka (semua itu) adalah dengan izin Allah; dan karena Dia hendak memberikan kehinaan kepada orang-orang fasik.\" (QS. Alhasyr 5), Abu Isa berkata; hadits ini adalah hadits hasan shahih."}],"59:6":[{"p":"Bukhari","n":2863,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مُحَمَّدٍ الْفَرْوِيُّ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرٍ ذَكَرَ لِي ذِكْرًا مِنْ حَدِيثِهِ ذَلِكَ فَانْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى مَالِكِ بْنِ أَوْسٍ فَسَأَلْتُهُ عَنْ ذَلِكَ الْحَدِيثِ فَقَالَ مَالِكٌبَيْنَا أَنَا جَالِسٌ فِي أَهْلِي حِينَ مَتَعَ النَّهَارُ إِذَا رَسُولُ عُمَرَ بْنِ الْخَطَّابِ يَأْتِينِي فَقَالَ أَجِبْ أَمِيرَ الْمُؤْمِنِينَ فَانْطَلَقْتُ مَعَهُ حَتَّى أَدْخُلَ عَلَى عُمَرَ فَإِذَا هُوَ جَالِسٌ عَلَى رِمَالِ سَرِيرٍ لَيْسَ بَيْنَهُ وَبَيْنَهُ فِرَاشٌ مُتَّكِئٌ عَلَى وِسَادَةٍ مِنْ أَدَمٍ فَسَلَّمْتُ عَلَيْهِ ثُمَّ جَلَسْتُ فَقَالَ يَا مَالِ إِنَّهُ قَدِمَ عَلَيْنَا مِنْ قَوْمِكَ أَهْلُ أَبْيَاتٍ وَقَدْ أَمَرْتُ فِيهِمْ بِرَضْخٍ فَاقْبِضْهُ فَاقْسِمْهُ بَيْنَهُمْ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ لَوْ أَمَرْتَ بِهِ غَيْرِي قَالَ اقْبِضْهُ أَيُّهَا الْمَرْءُ فَبَيْنَا أَنَا جَالِسٌ عِنْدَهُ أَتَاهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَالزُّبَيْرِ وَسَعْدِ بْنِ أَبِي وَقَّاصٍ يَسْتَأْذِنُونَ قَالَ نَعَمْ فَأَذِنَ لَهُمْ فَدَخَلُوا فَسَلَّمُوا وَجَلَسُوا ثُمَّ جَلَسَ يَرْفَا يَسِيرًا ثُمَّ قَالَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ قَالَ نَعَمْ فَأَذِنَ لَهُمَا فَدَخَلَا فَسَلَّمَا فَجَلَسَا فَقَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا وَهُمَا يَخْتَصِمَانِ فِيمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَالِ بَنِي النَّضِيرِ فَقَالَ الرَّهْطُ عُثْمَانُ وَأَصْحَابُهُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ قَالَ عُمَرُ تَيْدَكُمْ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُ قَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا اللَّهَ أَتَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ ذَلِكَ قَالَا قَدْ قَالَ ذَلِكَ قَالَ عُمَرُ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ قَدْ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْفَيْءِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ ثُمَّ قَرَأَ{ وَمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ قَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ ذَلِكَ قَالَ عُمَرُ ثُمَّ تَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهَا أَبُو بَكْرٍ فَعَمِلَ فِيهَا بِمَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ يَعْلَمُ إِنَّهُ فِيهَا لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَكُنْتُ أَنَا وَلِيَّ أَبِي بَكْرٍ فَقَبَضْتُهَا سَنَتَيْنِ مِنْ إِمَارَتِي أَعْمَلُ فِيهَا بِمَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا عَمِلَ فِيهَا أَبُو بَكْرٍ وَاللَّهُ يَعْلَمُ إِنِّي فِيهَا لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ جِئْتُمَانِي تُكَلِّمَانِي وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا وَاحِدٌ جِئْتَنِي يَا عَبَّاسُ تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكَ وَجَاءَنِي هَذَا يُرِيدُ عَلِيًّا يُرِيدُ نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ لَكُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ فَلَمَّا بَدَا لِي أَنْ أَدْفَعَهُ إِلَيْكُمَا قُلْتُ إِنْ شِئْتُمَا دَفَعْتُهَا إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهَا بِمَا عَمِلَ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِمَا عَمِلَ فِيهَا أَبُو بَكْرٍ وَبِمَا عَمِلْتُ فِيهَا مُنْذُ وَلِيتُهَا فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا فَبِذَلِكَ دَفَعْتُهَا إِلَيْكُمَا فَأَنْشُدُكُمْ بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْهِمَا بِذَلِكَ قَالَ الرَّهْطُ نَعَمْ ثُمَّ أَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ قَالَا نَعَمْ قَالَ فَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ فَإِنْ عَجَزْتُمَا عَنْهَا فَادْفَعَاهَا إِلَيَّ فَإِنِّي أَكْفِيكُمَاهَا","trj":"Telah bercerita kepada kami [Ishaq bin Muhammad Al Farwiy] telah bercerita kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Malik bin Aus Al Hadatsan], bahwa [Muhammad bin Jubair] menyebutkan kepadaku suatu cerita dari hadits yang disampaikannya maka aku berangkat menemui Malik bin Aus lalu aku bertanya kepadanya tentang hadits yang dimaksud, maka Malik berkata; \"Ketika aku sedang duduk bersama keluargaku di tengah hari tiba-tiba datang utusan 'Umar bin Al Khaththab menemuiku lalu berkata; \"Penuhilah panggilan Amirul Mu'minin\". Maka aku pergi bersamanya menemui ['Umar] yang ketika itu sedang duduk di atas tikar yang tidak dialasi kasur namun bersandar pada bantal terbuat dari kulit. Aku memberi salam kepadanya lalu duduk. Maka dia berkata; \"Wahai Maal (Malik), sesungguhnya telah datang kepada kami para ahli bait dari kaummu dan aku sudah memerintahkan untuk memberi mereka pemberian yang sedikit dan tidak bernilai, maka terimalah ini dan bagikanlah kepada mereka\". Aku berkata; \"Wahai Amirul Mu'minin, andai engkau perintahkan hal ini kepada selain aku\". Dia berkata; \"Terimalah, hai laki-laki\". Di tengah aku sedang duduk bersamanya, datang kepadanya penjaga pintu yang bernama Yarfaa lalu berkata; \"Apakah kamu membolehkan ['Utsman], ['Abdur Rahman bin 'Auf], [Az Zubair] dan [Sa'ad bin Abi Waqash], mereka minta izin masuk\". 'Umar menjawab; \"Ya\". Lalu dia mengizinkan mereka masuk. Maka mereka masuk dan memberi salam lalu duduk. Begitu juga Yarfaa duduk sebentar lalu berkata; \"Apakah kamu juga membolehkan ['Ali] dan ['Abbas] masuk?\". 'Umar menjawab; \"Ya\". Lalu 'Umar mengizinkan keduanya masuk. Keduanya pun masuk dan memberi salam lalu duduk. 'Abbas berkata; \"Wahai Amirul Mu'minin, putuskanlah antara aku dan orang ini\". Keduanya sedang bertengkar urusan harta yang Allah karuniakan kepada Rasulullah Shallallahu'alaiwasallam berupa fa'i dari harta Bani an-Nadlir. Kelompok orang yang bersama 'Utsman dan para shohabatnya berkata; \"Wahai Amirul Mu'minin, putuskanlah perkara mereka berdua dan legakanlah salah seorang diantara keduanya\". 'Umar berkata; \"Tenanglah kalian!. Dan aku aku minta kepada kalian, demi Allah yang dengan izin-Nya tegak langit dan bumi, apakah kalian mengetahui bahwa Rasulullah Shallallahu'alaiwasallam telah bersabda: \"Kami tidak mewariskan, Apa-apa yang kami tinggalkan menjadi shadaqah?\". Yang Rasulullah Shallallahu'alaiwasallam maksudkan (dengan kata kami) adalah diri Beliau sendiri. Kelompok ('Utsman) berkata; \"Ya, Beliau sudah bersabda demikian\". Maka 'Umar kembali menghadap dan berbicara kepada 'Ali dan 'Abbas; \"Aku minta kepada kalian berdua, demi Allah, apakah kalian berdua mengetahui bahwa Rasulullah Shallallahu'alaiwasallam telah bersabda seperti itu?\". Keduanya menjawab; \"Ya, Beliau sudah bersabda demikian\". 'Umar kemudian berkata; \"Untuk itu aku akan berbicara kepada kalian tentang masalah ini. Sesungguhnya Allah tekah mengkhusukan Rasul-Nya Shallallahu'alaihiwasallam dalam masalah fa'i ini sebagai sesuatu yang tidak Dia berikan kepada siapapun selain Beliau Shallallahu'alaihiwasallam\". Lalu 'Umar membaca firman Allah (QS Al Hasyr ayat 6 yang artinya: (\"Dan apa saja yang dikaruniakan Allah berupa fa'i (rampasan perang) kepada Rasul-Nya dari (harta benda) mereka…) hingga firman-Nya (dan Allah Maha berkuasa atas segala sesuatu\"), ayat ini merupakan kekhususan buat Rasulullah Shallallahu'alaiwasallam. Demi Allah, tidaklah Beliau mengumpulkannya dengan mengabaikan kalian dan juga tidak untuk lebih mementingkan kalian. Sungguh Beliau telah memberikannya kepada kalian dan menyebarkannya di tengah-tengah kalian (kaum Muslimin) dan hingga sekarang masih ada yang tersisa dari harta tersebut. Dan Rasulullah Shallallahu'alaiwasallam telah memberi nafkah belanja kepada keluarga Beliau sebagai nafkah tahunan mereka dari harta fa'i ini lalu sisanya Beliau ambil dan dijadikannya sebagai harta Allah dan Beliau sudah menerapkan semua ini selama hidup Beliau. Aku tanya kepda kalian, bukankah kalian sudah mengetahui ini semua?\". Mereka menjawab; \"Ya. Lalu 'Umar berbicara kepada 'Ali dan 'Abbas; \"Aku tanya kepada kalian berdua, bukankah kamu berdua sudah mengetahui ini semua?\". 'Umar melanjutkan; \"Kemudian Allah mewafatkan Nabi-Nya Shallallahu'alaihiwasallam, kemudian Abu Bakr berkata; \"Akulah wali Rasulullah Shallallahu'alaiwasallam. Lalu Abu Bakr menjadi yang memegang kepemimpinan, maka dia melaksanakan seperti apa yang dilaksanakan oleh Rasulullah Shallallahu'alaiwasallam dan apa yang telah dilakukan oleh Abu Bakr, sungguh Allah mengetahuinya, bahwa aku dalam perkara ini berpendapat bahwa dia orang yang jujur, bijak, lurus dan pengikut kebenaran. Lalu kalian berdua datang kepadaku dan berbicara kepadaku, sedang ucapan kalian satu dan maksud urusan kalian juga satu. Engkau, wahai 'Abbas, datang kepadaku meminta kepadaku bagian dari anak saudara kamu. Dan orang ini, yang 'Umar maksud adalah 'Ali, datang meminta bagian istrinya dari ayahnya. Aku katakan kepada kalian berdua, sesungguhnya Rasulullah Shallallahu'alaiwasallam telah bersabda: \"Kami tidak mewariskan. Apa-apa yang kami tinggalkan menjadi shadaqah\". Setelah jelas bagiku bahwa aku harus memberikannya kepada kalian berdua maka aku akan katakan, jika memang kalian menghendakinya aku akan berikan kepada kalian berdua namun wajib kalian berdua ingat janji Allah dan ketentuan-Nya bahwa kalian sungguh mengetahui tentang urusan ini apa yang telah Rasulullah Shallallahu'alaiwasallam lakukan dan apa yang telah Abu Bakr lakukan, dan juga apa yang telah aku lakukan sejak aku memegang kekuasaan ini dan jika kalian berdua mengatakan berikanlah kepada kami, maka dengan ketentuan seperti itu aku akan berikan kepada kalian berdua. Dan aku ingatkan kepada kalian semua, demi Allah, apakah aku berikan kepada keduanya dengan ketentuan seperti ini. Kelompok 'Utsman berkata; \"Ya\". Kemudian 'Umar menghadap 'Ali dan 'Abbas seraya berkata; \"Aku ingatkan kalian berdua, demi Allah, apakah aku memberikannya kepada kalian berdua berdasarkan ketentuan ini?\". Keduanya menjawab; \"Ya\". 'Selanjutnya 'Umar berkata; \"Lalu kalian menghampiri aku agar aku memutuskan perkara ini dengan ketentuan lain. Sungguh demi Allah yang dengan izin-Nya tegaklah langit dan bumi, aku tidak akan pernah memutuskan masalah ini dengan selain ketentuan ini. Seandainya kalian berdua tidak sanggup atasnya maka serahkanlah kepadaku karena sungguh aku akan mengganti kalian untuk mengurus harta itu.\""},{"p":"Bukhari","n":3530,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ النَّصْرِيُّ أَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُدَعَاهُ إِذْ جَاءَهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ يَسْتَأْذِنُونَ فَقَالَ نَعَمْ فَأَدْخِلْهُمْ فَلَبِثَ قَلِيلًا ثُمَّ جَاءَ فَقَالَ هَلْ لَكَ فِي عَبَّاسٍ وَعَلِيٍّ يَسْتَأْذِنَانِ قَالَ نَعَمْ فَلَمَّا دَخَلَا قَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا وَهُمَا يَخْتَصِمَانِ فِي الَّذِي أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَنِي النَّضِيرِ فَاسْتَبَّ عَلِيٌّ وَعَبَّاسٌ فَقَالَ الرَّهْطُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ فَقَالَ عُمَرُ اتَّئِدُوا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ بِذَلِكَ نَفْسَهُ قَالُوا قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَبَّاسٍ وَعَلِيٍّ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ ذَلِكَ قَالَا نَعَمْ قَالَ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ سُبْحَانَهُ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْفَيْءِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ فَقَالَ جَلَّ ذِكْرُهُ{ وَمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَهَا عَلَيْكُمْ لَقَدْ أَعْطَاكُمُوهَا وَقَسَمَهَا فِيكُمْ حَتَّى بَقِيَ هَذَا الْمَالُ مِنْهَا فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيَاتَهُ ثُمَّ تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ فَأَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهُ أَبُو بَكْرٍ فَعَمِلَ فِيهِ بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمْ حِينَئِذٍ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ وَقَالَ تَذْكُرَانِ أَنَّ أَبَا بَكْرٍ فِيهِ كَمَا تَقُولَانِ وَاللَّهُ يَعْلَمُ إِنَّهُ فِيهِ لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ فَقَبَضْتُهُ سَنَتَيْنِ مِنْ إِمَارَتِي أَعْمَلُ فِيهِ بِمَا عَمِلَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَاللَّهُ يَعْلَمُ أَنِّي فِيهِ صَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ جِئْتُمَانِي كِلَاكُمَا وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا جَمِيعٌ فَجِئْتَنِي يَعْنِي عَبَّاسًا فَقُلْتُ لَكُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ فَلَمَّا بَدَا لِي أَنْ أَدْفَعَهُ إِلَيْكُمَا قُلْتُ إِنْ شِئْتُمَا دَفَعْتُهُ إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهِ بِمَا عَمِلَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَمَا عَمِلْتُ فِيهِ مُنْذُ وَلِيتُ وَإِلَّا فَلَا تُكَلِّمَانِي فَقُلْتُمَا ادْفَعْهُ إِلَيْنَا بِذَلِكَ فَدَفَعْتُهُ إِلَيْكُمَا أَفَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهِ بِقَضَاءٍ غَيْرِ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهُ فَادْفَعَا إِلَيَّ فَأَنَا أَكْفِيكُمَاهُقَالَ فَحَدَّثْتُ هَذَا الْحَدِيثَ عُرْوَةَ بْنَ الزُّبَيْرِ فَقَالَ صَدَقَ مَالِكُ بْنُ أَوْسٍ أَنَا سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُ أَرْسَلَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُثْمَانَ إِلَى أَبِي بَكْرٍ يَسْأَلْنَهُ ثُمُنَهُنَّ مِمَّا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ أَنَا أَرُدُّهُنَّ فَقُلْتُ لَهُنَّ أَلَا تَتَّقِينَ اللَّهَ أَلَمْ تَعْلَمْنَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ بِذَلِكَ نَفْسَهُ إِنَّمَا يَأْكُلُ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَالِ فَانْتَهَى أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَا أَخْبَرَتْهُنَّ قَالَ فَكَانَتْ هَذِهِ الصَّدَقَةُ بِيَدِ عَلِيٍّ مَنَعَهَا عَلِيٌّ عَبَّاسًا فَغَلَبَهُ عَلَيْهَا ثُمَّ كَانَ بِيَدِ حَسَنِ بْنِ عَلِيٍّ ثُمَّ بِيَدِ حُسَيْنِ بْنِ عَلِيٍّ ثُمَّ بِيَدِ عَلِيِّ بْنِ حُسَيْنٍ وَحَسَنِ بْنِ حَسَنٍ كِلَاهُمَا كَانَا يَتَدَاوَلَانِهَا ثُمَّ بِيَدِ زَيْدِ بْنِ حَسَنٍ وَهِيَ صَدَقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقًّا","trj":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata, telah mengabarkan kepadaku [Malik bin Aus bin Al Hadatsan] bahwa [Umar bin Al Khattab] radliallahu 'anhu pernah memanggilnya, setelah itu penjaga pintunya, Yarfa, datang melapor, \"Apakah anda mengizinkan [Utsman], [Abdurrahman], [Zubair] dan [Sa'd] untuk masuk?\" Umar menjawab, \"Ya.\" Kemudian penjaga pintu menyuruh mereka masuk, tidak lama kemudian penjaga pintu datang lagi dan berkata, 'Apakah anda mengizinkan [Abbas] dan [Ali] untuk masuk?\" Umar menjawab, \"Ya.\" Ketika keduanya telah masuk, Abbas berkata, \"Wahai Amirul Mukminin, putuskanlah antara kami dengan orang ini.\" Ketika itu mereka tengah berselisih masalah harta yang Allah karuniakan kepada Rasul-Nya shallallahu 'alaihi wasallam, yakni berupa harta milik Bani Nadlir hingga keduanya saling mencela. Sebagian kelompok berkata, \"Wahai Amirul mukminin, buatlah keputusan untuk keduanya, dan legakanlah salah seorang di antara keduanya.\" 'Umar pun berkata, \"Tenanglah kalian! Dan aku minta kepada kalian, demi Allah yang dengan izin-Nya langit dan bumi tegak, apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak mewariskan. Dan apa-apa yang kami tinggalkan menjadi sedekah.\" Yang beliau maksudkan (dengan kata kami) adalah diri beliau sendiri. Mereka menjawab, \"Ya, beliau telah bersabda demikian.\" Maka 'Umar kembali menghadap dan berbicara kepada 'Ali dan 'Abbas, \"Aku minta kepada kalian berdua, demi Allah, apakah kalian berdua mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda seperti itu?\" Keduanya menjawab, \"Ya, beliau telah bersabda seperti itu.\" Umar kemudian melanjutkan, \"Untuk itu aku akan menyampaikan kepada kalian tentang masalah ini. Sesungguhnya Allah telah mengkhususkan Rasul-Nya shallallahu 'alaihi wasallam dalam masalah fa'i ini sebagai sesuatu yang tidak Dia berikan kepada siapapun selain beliau.\" Lalu Umar membaca firman Allah: '(Dan apa saja yang dikaruniakan Allah berupa fa'i (rampasan perang) kepada Rasul-Nya dari (harta benda) mereka… -hingga firmanNya- dan Allah Maha berkuasa atas segala sesuatu) ' (Qs. Al Hasyr: 6), ayat ini merupakan pengkhususan untuk Rasulullah shallallahu 'alaihi wasallam. Demi Allah, tidaklah beliau mengumpulkannya dengan tidak memperhatikan kalian dan juga tidak untuk lebih mementingkan diri kalian. Sungguh, beliau telah memberikannya kepada kalian dan menyebarkannya di tengah-tengah kalian (kaum Muslimin) hingga sekarang masih ada yang tersisa dari harta tersebut. Dan Rasulullah shallallahu 'alaihi wasallam telah memberi nafkah belanja kepada keluarga beliau sebagai nafkah tahunan mereka dari harta fa'i ini, lalu sisanya beliau ambil dan dijadikannya sebagai harta Allah, beliau sudah menerapkan semua ini samasa hidup beliau. Kemudian Nabi shallallahu 'alaihi wasallam wafat, lalu Abu Bakr berkata, 'Akulah wali Rasulullah shallallahu 'alaihi wasallam.' Maka Abu Bakr pun mewenangi harta itu, kemudian ia mengelolanya seperti apa yang dilaksanakan oleh Rasulullah shallallahu 'alaihi wasallam, saat itu kalian juga ada.\" Kemudian Umar menghadap ke arah arah Ali dan Abbas, dia berkata, \"Kalian berdua juga ingat bahwa dalam mengelola harta itu sebagaimana yang kalian berdua katakan, sungguh Allah juga Maha tahu, bahwa dia adalah orang yang jujur, bijak, lurus dan pengikut kebenaran. Kemudian Allah mewafatkan Abu Bakr, lalu aku berkata, 'Aku adalah pengganti Rasulullah shallallahu 'alaihi wasallam dan Abu Bakr, ' dan aku berwenang untuk mengelola harta tersebut hingga dua tahun dari kepemimpinanku, aku mengelolanya sebagaimana yang dikelola Rasulullah shallallahu 'alaihi wasallam dan Abu Bakr. Dan Allah juga mengetahui bila aku adalah sosok yang jujur, bijak, lurus dan pengikut kebenaran, lalu kenapa kalian datang kepadaku dan berbicara kepadaku padahal ucapan kalian satu dan maksud urusan kalian juga satu. Engkau, wahai 'Abbas, kau datang kepadaku lalu aku katakan kepada kalian berdua, 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak mewariskan. Apa-apa yang kami tinggalkan menjadi sedekah.\" Setelah jelas bagiku bahwa aku harus memberikannya kepada kalian berdua, maka aku akan katakan, Jika memang kalian menghendakinya aku akan berikan kepada kalian berdua, namun kalian berdua harus ingat akan janji Allah dan ketentuan-Nya, yaitu kalian harus mengelola sebagaimana yang pernah dikelola Rasulullah shallallahu 'alaihi wasallam, Abu Bakr lakukan dan juga apa yang telah aku lakukan sejak aku memegang kekuasaan ini, jika tidak, maka kalian jangan mengatakan sesuatu kepadaku, jika kalian berdua mengatakan, \"Berikanlah kepada kami, \" maka dengan ketentuan seperti itu, aku akan berikan kepada kalian berdua. Apakah kalian berdua hendak merubah ketentuan selain dari itu? Demi Allah, yang dengan izin-Nya langit dan bumi bias tegak, aku tidak akan memutuskan dengan keputusan selain itu sampai tiba hari Kiamat, seandainya kalian berdua tidak sanggup atasnya maka serahkanlah kepadaku karena sungguh aku akan mencukupkan kalian berdua dengannya (harta itu).\" Perawi berkata, \"Lalu aku sampaikan hadits ini kepada ['Urwah bin Az Zubair], dia menjawab, \"Malik bin Aus benar, aku juga pernah mendengar ['Aisyah] radliallahu 'anha, isteri Nabi shallallahu 'alaihi wasallam, berkata, \"Para isteri Nabi shallallahu 'alaihi wasallam pernah mengutus Utsman menemui Abu Bakr untuk meminta seperdelapan dari harta yang telah Allah karuniakan kepada Rasul-Nya shallallahu 'alaihi wasallam, lalu aku menolak mereka, aku katakan kepada mereka, \"Apakah kalian tidak takut kepada Allah? Apakah kalian tidak mengetahui bahwa Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi, dan yang kami tinggalkan adalah sedekah -yang beliau maksud dengan (kami) adalah diri beliau sendiri-, sesungguhnya keluarga Muhammad makan dari harta ini.\" Maka para isteri Nabi shallallahu 'alaihi wasallam berhenti pada apa yang telah disampaikan oleh Aisyah kepada mereka.\" Urwah berkata, \"Maka harta sedekah ini ada di tangan Ali, sementara Ali mencegah Abbas dari harta tersebut, dan dapat mengalahkannya, kemudian beralih ditangan Hasan bin Ali, kemudian berpindah ketangan Husain bin Ali, kemudian berpindah ke tangan Ali bin Husain, kemudian Al Hasan bin Al Hasan, keduanya saling bergantian, kemudian berpindah ke tangan Zaid bin Hasan, dan sesungguhnya itu merupakan sedekah Rasulullah shallallahu 'alaihi wasallam.\""}],"59:7":[{"p":"Abu Dawud","n":3524,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ قَالَ مُحَمَّدٌ وَالْوَاصِلَاتِ و قَالَ عُثْمَانُ وَالْمُتَنَمِّصَاتِ ثُمَّ اتَّفَقَا وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ عَزَّ وَجَلَّ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ زَادَ عُثْمَانُ كَانَتْ تَقْرَأُ الْقُرْآنَ ثُمَّ اتَّفَقَا فَأَتَتْهُ فَقَالَتْ بَلَغَنِي عَنْكَ أَنَّكَ لَعَنْتَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ قَالَ مُحَمَّدٌ وَالْوَاصِلَاتِ و قَالَ عُثْمَانُ وَالْمُتَنَمِّصَاتِ ثُمَّ اتَّفَقَا وَالْمُتَفَلِّجَاتِ قَالَ عُثْمَانُ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ تَعَالَى فَقَالَ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ تَعَالَى قَالَتْ لَقَدْ قَرَأْتُ مَا بَيْنَ لَوْحَيْ الْمُصْحَفِ فَمَا وَجَدْتُهُ فَقَالَ وَاللَّهِ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ ثُمَّ قَرَأَ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قَالَتْ إِنِّي أَرَى بَعْضَ هَذَا عَلَى امْرَأَتِكَ قَالَ فَادْخُلِي فَانْظُرِي فَدَخَلَتْ ثُمَّ خَرَجَتْ فَقَالَ مَا رَأَيْتِو قَالَ عُثْمَانُ فَقَالَتْ مَا رَأَيْتُ فَقَالَ لَوْ كَانَ ذَلِكَ مَا كَانَتْ مَعَنَا","trj":"Telah menceritakan kepada kami [Muhammad bin Isa] dan [Utsman bin Abu Syaibah] secara makna, keduanya berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Allah melaknat wanita yang mentato dan wanita yang minta untuk ditato.\" Muhammad menyebutkan, \"dan wanita yang meyambung rambut.\" Utsman menyebutkan, \"dan wanita yang mencukur bulu alis.\" Dan keduanya sepakat dengan penyebutan, \"dan mengikir gigi untuk kecantikan dengan merubah ciptaan Allah Azza Wa Jalla. Hadits ini kemudian di dengar oleh seorang wanita dari bani Asad yang biasa di panggil dengan nama Ummu Ya'qub, Utsman menambahkan, \"yang sedang membaca Al-Qur'an. Ia lalu mendatangi Abdullah dan berkata, \"Telah sampai kabar kepadaku bahwa engkau melaknat Wanita yang mentato dan wanita yang minta untuk ditato?\" Muhammad menyebutkan, \"dan wanita yang menyambung rambut.\" Utsman menyebutkan, \"dan wanita yang mencukur alis. Kemudian keduanya sepakat dengan penyebutan, \"wanita yang mengikir gigi, Utsman menyebutkan, \"untuk kecantikan dengan merubah ciptaan Allah Ta'ala.\" Ummu Ya'qub berkata, \"Aku telah membaca lembaran-lembaran Al-Qur'an tetapi aku tidak mendapatkannya.\" Abdullah berkata, \"Demi Allah, jika engkau membacanya, sungguh engkau pasti mendapatkannya.\" Kemudian Abdullah membaca: (Apa yang diberikan Rasul kepadamu maka terimalah dia, dan apa yang dilarangnya bagimu maka tinggalkanlah.. (Qs. Al Hasyr: 7).\" Ummu Ya'qub berkata, \"Aku melihat hal ini ada pada isterimu!\" Abdullah berkata, \"Masuk dan lihatlah.\" Ummu Ya'qub kemudian masuk dan keluar lagi. Abdullah berkata, \"Apa yang engkau lihat?\" Utsman berkata (dalam riwayatnya) maka Ummu Ya'qub berkata; \"Aku tidak melihatnya\", Ibnu Mas'ud berkata; \"Jikalau hal itu ada pada istriku niscaya dia tidak akan ada bersama kami.\""},{"p":"Bukhari","n":4202,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُوتَشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ فَجَاءَتْ فَقَالَتْ إِنَّهُ بَلَغَنِي عَنْكَ أَنَّكَ لَعَنْتَ كَيْتَ وَكَيْتَ فَقَالَ وَمَا لِي أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ هُوَ فِي كِتَابِ اللَّهِ فَقَالَتْ لَقَدْ قَرَأْتُ مَا بَيْنَ اللَّوْحَيْنِ فَمَا وَجَدْتُ فِيهِ مَا تَقُولُ قَالَ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ أَمَا قَرَأْتِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قَالَتْ بَلَى قَالَ فَإِنَّهُ قَدْ نَهَى عَنْهُ قَالَتْ فَإِنِّي أَرَى أَهْلَكَ يَفْعَلُونَهُ قَالَ فَاذْهَبِي فَانْظُرِي فَذَهَبَتْ فَنَظَرَتْ فَلَمْ تَرَ مِنْ حَاجَتِهَا شَيْئًا فَقَالَ لَوْ كَانَتْ كَذَلِكَ مَا جَامَعْتُهَا","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata, \"Semoga Allah melaknati Al Wasyimaat (wanita yang mentato) dan Al Mutawatasyimaat (wanita yang meminta untuk ditato), Al Mutanammishaat (wanita yang mencukur alisnya), serta Al Mutafallijaat (merenggangkan gigi) untuk keindahan, yang mereka merubah-rubah ciptaan Allah.\" Kemudian ungkapan itu sampai kepada salah seorang wanita dari Bani Asad yang biasa dipanggil Ummu Ya'qub. Lalu wanita itu pun datang dan berkata, \"Telah sampai kepadaku berita tentang Anda. Bahwa Anda telah melaknat yang ini dan itu.\" Abdullah berkata, \"Mengapakah aku tidak melaknat mereka yang telah dilaknat oleh Rasulullah shallallahu 'alaihi wasallam dan mereka yang terdapat di dalam Kitabullah?.\" Kemudian wanita berkata, \"Sungguh, aku telah membaca di atara kedua lembarannya, namun di dalamnya aku tidaklah mendapatkan apa yang telah Anda katakan.\" Abdullah menjelaskan, \"Sekiranya Anda membacanya secara keseluruhan, maka niscaya saudari akan menemukannya. Bukankah Allah telah berfirman: 'Apa yang dibawa Rasul untuk kalian, maka ambillah, sedangkan apa yang dilarangnya, maka tingalkanlah? '\" (QS. Alhasyr 7). Wanita itu menjawab, \"Ya, benar.\" Abdullah melanjutkan, \"Sesungguhnya beliau telah melarang hal itu.\" Wanita itu kembali berkata, \"Tetapi, sesungguhnya aku menduga kuat, bahwa isteri anda sendiri melakukan hal itu.\" Abdullah berkata, \"Kalau itu anggapanmu, berangkatlah dan lihatlah.\" Lalu wanita itu pun pergi untuk melihatnya, namun ternyata tidak mendapatkan kebenaran dugaannya sedikit pun. Kemudian Abdullah pun berkata, \"Sekiranya isteriku seperti itu, niscaya aku tidak akan mencampurinya.\""},{"p":"Bukhari","n":5178,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَلَعَنَ عَبْدُ اللَّهِ الْوَاشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَقَالَتْ أُمُّ يَعْقُوبَ مَا هَذَا قَالَ عَبْدُ اللَّهِ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ وَفِي كِتَابِ اللَّهِ قَالَتْ وَاللَّهِ لَقَدْ قَرَأْتُ مَا بَيْنَ اللَّوْحَيْنِ فَمَا وَجَدْتُهُ قَالَ وَاللَّهِ لَئِنْ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dia berkata; [Abdullah] melaknat orang yang mentato, mencukur habis alis mata, merenggangkan gigi (denga kawat dll) untuk kecantikan dengan merubah ciptaan Allah, Ummu Ya'qub berkata; \"Apa maksudnya ini?\" Abdullah mengatakan; \"Bagaimana aku tidak melaknat orang yang dilaknat Rasulullah dan telah tercatat pula dalam kitabullah. Ummu Ya'qub berkata; \"Saya telah membaca dalam mushaf, namun saya tidak mendapatkan hal itu.\" Abdullah berkata; \"Demi Allah, sekiranya kamu membacanya, niscaya kamu akan mendapatkannya yaitu Dan sesuatu yang datang dari Rasul maka ambillah dan yang di larang olehnya maka jauhilah QS Al Hasyr: 7."},{"p":"Muslim","n":3069,"ar":"و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ الضُّبَعِيُّ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَنَّ مَالِكَ بْنَ أَوْسٍ حَدَّثَهُ قَالَ أَرْسَلَ إِلَيَّ عُمَرُ بْنُ الْخَطَّابِ فَجِئْتُهُ حِينَ تَعَالَى النَّهَارُ قَالَ فَوَجَدْتُهُ فِي بَيْتِهِ جَالِسًا عَلَى سَرِيرٍ مُفْضِيًا إِلَى رُمَالِهِ مُتَّكِئًا عَلَى وِسَادَةٍ مِنْ أَدَمٍ فَقَالَ لِي يَا مَالُ إِنَّهُ قَدْ دَفَّ أَهْلُ أَبْيَاتٍ مِنْ قَوْمِكَ وَقَدْ أَمَرْتُ فِيهِمْ بِرَضْخٍ فَخُذْهُ فَاقْسِمْهُ بَيْنَهُمْ قَالَ قُلْتُ لَوْ أَمَرْتَ بِهَذَا غَيْرِي قَالَ خُذْهُ يَا مَالُ قَالَ فَجَاءَ يَرْفَا فَقَالَ هَلْ لَكَ يَا أَمِيرَ الْمُؤْمِنِينَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَالزُّبَيْرِ وَسَعْدٍ فَقَالَ عُمَرُ نَعَمْ فَأَذِنَ لَهُمْ فَدَخَلُوا ثُمَّ جَاءَ فَقَالَ هَلْ لَكَ فِي عَبَّاسٍ وَعَلِيٍّ قَالَ نَعَمْ فَأَذِنَ لَهُمَا فَقَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا الْكَاذِبِ الْآثِمِ الْغَادِرِ الْخَائِنِ فَقَالَ الْقَوْمُ أَجَلْ يَا أَمِيرَ الْمُؤْمِنِينَ فَاقْضِ بَيْنَهُمْ وَأَرِحْهُمْ فَقَالَ مَالِكُ بْنُ أَوْسٍ يُخَيَّلُ إِلَيَّ أَنَّهُمْ قَدْ كَانُوا قَدَّمُوهُمْ لِذَلِكَفَقَالَ عُمَرُ اتَّئِدَا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالُوا نَعَمْ ثُمَّ أَقْبَلَ عَلَى الْعَبَّاسِ وَعَلِيٍّ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَاهُ صَدَقَةٌ قَالَا نَعَمْ فَقَالَ عُمَرُ إِنَّ اللَّهَ جَلَّ وَعَزَّ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَاصَّةٍ لَمْ يُخَصِّصْ بِهَا أَحَدًا غَيْرَهُ قَالَ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْ أَهْلِ الْقُرَى فَلِلَّهِ وَلِلرَّسُولِ }مَا أَدْرِي هَلْ قَرَأَ الْآيَةَ الَّتِي قَبْلَهَا أَمْ لَا قَالَ فَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَكُمْ أَمْوَالَ بَنِي النَّضِيرِ فَوَاللَّهِ مَا اسْتَأْثَرَ عَلَيْكُمْ وَلَا أَخَذَهَا دُونَكُمْ حَتَّى بَقِيَ هَذَا الْمَالُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُ مِنْهُ نَفَقَةَ سَنَةٍ ثُمَّ يَجْعَلُ مَا بَقِيَ أُسْوَةَ الْمَالِ ثُمَّ قَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ نَشَدَ عَبَّاسًا وَعَلِيًّا بِمِثْلِ مَا نَشَدَ بِهِ الْقَوْمَ أَتَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ قَالَ فَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْتُمَا تَطْلُبُ مِيرَاثَكَ مِنْ ابْنِ أَخِيكَ وَيَطْلُبُ هَذَا مِيرَاثَ امْرَأَتِهِ مِنْ أَبِيهَا فَقَالَ أَبُو بَكْرٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نُورَثُ مَا تَرَكْنَاهُ صَدَقَةٌ فَرَأَيْتُمَاهُ كَاذِبًا آثِمًا غَادِرًا خَائِنًا وَاللَّهُ يَعْلَمُ إِنَّهُ لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تُوُفِّيَ أَبُو بَكْرٍ وَأَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَلِيُّ أَبِي بَكْرٍ فَرَأَيْتُمَانِي كَاذِبًا آثِمًا غَادِرًا خَائِنًا وَاللَّهُ يَعْلَمُ إِنِّي لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ فَوَلِيتُهَا ثُمَّ جِئْتَنِي أَنْتَ وَهَذَا وَأَنْتُمَا جَمِيعٌ وَأَمْرُكُمَا وَاحِدٌ فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا فَقُلْتُ إِنْ شِئْتُمْ دَفَعْتُهَا إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ أَنْ تَعْمَلَا فِيهَا بِالَّذِي كَانَ يَعْمَلُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذْتُمَاهَا بِذَلِكَ قَالَ أَكَذَلِكَ قَالَا نَعَمْ قَالَ ثُمَّ جِئْتُمَانِي لِأَقْضِيَ بَيْنَكُمَا وَلَا وَاللَّهِ لَا أَقْضِي بَيْنَكُمَا بِغَيْرِ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهَا فَرُدَّاهَا إِلَيَّحَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَالَ أَرْسَلَ إِلَيَّ عُمَرُ بْنُ الْخَطَّابِ فَقَالَ إِنَّهُ قَدْ حَضَرَ أَهْلُ أَبْيَاتٍ مِنْ قَوْمِكَ بِنَحْوِ حَدِيثِ مَالِكٍ غَيْرَ أَنَّ فِيهِ فَكَانَ يُنْفِقُ عَلَى أَهْلِهِ مِنْهُ سَنَةً وَرُبَّمَا قَالَ مَعْمَرٌ يَحْبِسُ قُوتَ أَهْلِهِ مِنْهُ سَنَةً ثُمَّ يَجْعَلُ مَا بَقِيَ مِنْهُ مَجْعَلَ مَالِ اللَّهِ عَزَّ وَجَلَّ","trj":"Dan telah menceritakan kepadaku [Abdullah bin Muhammad bin Asma Adl dluba'i] telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [Az Zuhri] bahwa [Malik bin Aus] telah menceritakan kepadanya, katanya, \" [Umar bin Khattab] mengundangku, lalu aku datang kepadanya ketika hari mulai panas.\" Malik bin Aus berkata, \"Aku menemukan dia di rumahnya sedang duduk di atas ranjang yang langsung menyentuh tanah, dan bertelekan di atas bantas yang terbuat dari kulit.\" Dia berkata kepadaku, \"Wahai Malik, sesungguhnya kaummu bersama keluarganya telah datang dengan perjalanan yang sangat cepat. Dan aku telah memerintahkan untuk membagikan sesuatu kepada mereka, oleh karena itu bagikanlah (harta rampasan) kepada mereka.\" Malik bin Aus berkata, \"Aku berkata, \"Lebih baik anda memerintahkan orang lain selainku.\" Umar berkata, \"Ambillah wahai Malik.\" Malik bin Aus berkata, \"Lalu datanglah Yarfa seraya berkata, \"Wahai Amirul Mukminin, apakah [Utsman bin 'Affan], [Abdurrahman bin 'Auf], [Zubair bin 'Awwam] dan [Sa'd] boleh masuk?\" Umar menjawab, \"Ya, persilahkanlah mereka masuk.\" Kemudian mereka masuk, setelah itu Yarfa datang lagi saraya berkata, \"Apakah [Ali] dan [Abbas] boleh masuk?\" Umar menjawab, \"Ya, boleh.\" Keduanya pun diizinkan masuk. Lalu Abbas berkata, \"Wahai Amirul Mukminin, berilah keputusan hukum antara aku dengan pendusta, pengkhianat dan pendosa ini.\" Maka sebagian kaum berkata, \"Benar wahai Amirul Mukminin, berilah keputusan terhadapnya dan selesaikanlah urusannya.\" Malik bin Aus berkata, \"Aku berperasangka bahwa Abbas dan Ali yang menggiring rombongan terebut datang.\" Umar berkata, \"Tenanglah kalian berdua, aku memohon kebaikan untuk kalian kepada Allah yang atas izin-Nya berdiri langit dan bumi, apakah kalian tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi sesuatu pun, dan yang kami tinggalkan hanya berupa sedekah.\" Mereka menjawab, \"Benar.\" Kemudian Umar menghadap kepada Ali dan Abbas seraya berkata, \"Aku memohon kebaikan untuk kalian kepada Allah yang atas izin-Nya berdiri langit dan bumi, apakah kalian tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi sesuatu pun, dan yang kami tinggalkan hanya berupa sedekah.\" Abbas dan Ali berkata, \"Ya, benar.\" Umar lantas berkata, \"Sesungguhnya Allah Azza Wa Jalla memberikan kekhususan kepada Rasul-Nya shallallahu 'alaihi wasallam yang tidak diberikan kepada orang lain, Allah berfirman: '(Dan apa saja harta rampasan yang diberikan Allah kepada Rasul-Nya maka harta tersebut untuk Allah dan rasul-Nya …) ' (Qs. Al Hasyr: 7) -aku tidak tahu apakah Umar membaca ayat sebelumnya ataukah tidak-, Umar berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam membagi harta Bani Nadlir kepada kalian. Demi Allah, beliau tidak membuat pemberian itu untuk dirinya sendiri tanpa kalian, sehingga harta itu masih tersisa. Rasulullah shallallahu 'alaihi wasallam mengambil harta tersebut untuk menafkahi keluarganya selama setahun, dan selebihnya beliau menjadikan sebagai harta untuk kemaslahatan umum.\" Kemudian Umar berkata, \"Aku bertanya kepada kalian semua dengan izin Allah yang atas izin-Nya langit dan bumi berdiri, apakah kalian telah mengetahui hal itu?\" mereka menjawab, \"Ya, benar.\" Kemudian dia menghadap ke arah Abbas dan Ali sebagaimana perkataannya kepada rombongan kaum tersebut, \"Apakah kalian berdua mengetahui hal itu?\" keduanya menjawab, \"Ya, benar.\" Umar melanjutkan, \"Ketika Rasulullah shallallahu 'alaihi wasallam wafat, [Abu Bakar] berkata, \"Aku adalah pengganti Rasulullah shallallahu 'alaihi wasallam, kemudian masing-masing dari kalian berdua meminta harta peninggalannya dari anak pamanmu sedangkan yang ini (Ali) menuntut warisan isterinya dari ayahnya, maka Abu Bakar berkata, \"Bukankah Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Kami tidak mewarisi sesuatu apapun, namun yang kami tinggalkan hanyalah berupa sedekah.\" Apakah kalian berdua melihatnya ia seorang pendusta, pendosa dan seorang pengkhianat! Demi Allah, Dia tahu bahwa Abu Bakar adalah orang yang jujur, baik, berakal dan patuh terhadap kebenaran, setelah Abu Bakar wafat, maka akulah pengganti Rasulullah shallallahu 'alaihi wasallam dan pengganti Abu Bakar, maka apakah kalian berdua melihatku seorang pendusta, pendosa dan seorang pengkhianat! Demi Allah, Dia lebih tahu bahwa aku adalah orang yang jujur, baik dan berakal serta mengikuti kebenaran, namun kalian berdua berpaling dariku. Kemudian datang kepadaku, kamu berdua dan ini dan semuanya datang sedangkan perkara kalian hanya satu. Kalian berdua bertanya kepadaku, lalu aku menjawab, \"Jika kalian ingin bagian tersebut aku bagikan kepada kalian, maka kalian harus menggunakannya sesuai dengan yang telah dilakukan Rasulullah shallallahu 'alaihi wasallam, dan kalian mengambil bagian itu sesuai dengan perjanjian yang ada. Tetapi, sekarang kalian datang kepadaku agar aku memberikan keputusan di antara kalian berdua dengan keputusan yang tidak sesuai dengan perjanjian itu. Demi Allah, aku tidak akan memberikan keputusan selain sesuai dengan perjanjian tersebut hingga hari Kiamat. Jika kalian tidak mampu memenuhi persyaratan itu, maka kembalikanlah bagian itu kepadaku.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin rafi'] dan [Abd bin Humaid], [Ibnu Rafi'] berkata; telah menceritakan kepada kami, sedangkan yang dua mengatakan; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Malik bin Aus bin Al Haddatsan] dia berkata, \"Umar bin Khattab mengutus kepadaku seraya berkata, \"Sesungguhnya orang-orang dari beberapa keluarga dari kaummu …seperti hadits Malik, namun dalam haditsnya disebutkan, \"Dengannya beliau menafkahi keluarganya selama setahun.\" Dan sepertinya Ma'mar mengatakan, \"Beliau memberikan nafkah darinya kepada keluarganya selama setahun, kemudian beliau menjadikan sisa dari harta tersebut sebagai harta Allah Azza Wa Jalla.\""},{"p":"Muslim","n":3661,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ وَاللَّفْظُ لِإِسْحَقَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالنَّامِصَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ قَالَ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ وَكَانَتْ تَقْرَأُ الْقُرْآنَ فَأَتَتْهُ فَقَالَتْ مَا حَدِيثٌ بَلَغَنِي عَنْكَ أَنَّكَ لَعَنْتَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَقَالَ عَبْدُ اللَّهِ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ فَقَالَتْ الْمَرْأَةُ لَقَدْ قَرَأْتُ مَا بَيْنَ لَوْحَيْ الْمُصْحَفِ فَمَا وَجَدْتُهُ فَقَالَ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }فَقَالَتْ الْمَرْأَةُ فَإِنِّي أَرَى شَيْئًا مِنْ هَذَا عَلَى امْرَأَتِكَ الْآنَ قَالَ اذْهَبِي فَانْظُرِي قَالَ فَدَخَلَتْ عَلَى امْرَأَةِ عَبْدِ اللَّهِ فَلَمْ تَرَ شَيْئًا فَجَاءَتْ إِلَيْهِ فَقَالَتْ مَا رَأَيْتُ شَيْئًا فَقَالَ أَمَا لَوْ كَانَ ذَلِكَ لَمْ نُجَامِعْهَاحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ وَهُوَ ابْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا مُفَضَّلٌ وَهُوَ ابْنُ مُهَلْهِلٍ كِلَاهُمَا عَنْ مَنْصُورٍ فِي هَذَا الْإِسْنَادِ بِمَعْنَى حَدِيثِ جَرِيرٍ غَيْرَ أَنَّ فِي حَدِيثِ سُفْيَانَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَفِي حَدِيثِ مُفَضَّلٍ الْوَاشِمَاتِ وَالْمَوْشُومَاتِ و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ بِهَذَا الْإِسْنَادِ الْحَدِيثَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُجَرَّدًا عَنْ سَائِرِ الْقِصَّةِ مِنْ ذِكْرِ أُمِّ يَعْقُوبَ و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِهِمْ","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan ['Utsman bin Abu Syaibah]; Dan lafazh ini miliknya Ishaq; Telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] ia berkata; \"Allah telah mengutuk orang-orang yang membuat tato dan orang yang minta dibuatkan tato, orang-orang yang mencabut bulu mata, orang-orang yang minta dicabut bulu matanya, dan orang-orang yang merenggangkan gigi demi kecantikan yang merubah ciptaan Allah.\" Ternyata ucapan 'Abdullah bin Mas'ud itu sampai kepada seorang wanita dari Bani Asad yang biasa dipanggil Ummu Ya'qub yang pada saat itu sedang membaca Al Qur'an. Kemudian wanita itu datang kepada Ibnu Mas'ud sambil berkata; 'Hai 'Abdullah, apakah benar berita yang sampai kepadaku bahwasanya kamu mengutuk orang-orang yang minta dicabut bulu mata wajahnya dan orang yang merenggangkan giginya demi kecantikan dan merubah ciptaan Allah? ' Abdullah bin Mas'ud menjawab; 'Bagaimana aku tidak akan mengutuk orang-orang yang dikutuk oleh Rasulullah shallallahu 'alaihi wasallam, sedangkan hal itu ada dalam Al Qur'an? ' Wanita itu membantah; 'Aku sudah membaca semua ayat yang ada di antara sampul mushaf, tetapi aku tidak menemukannya.' Ibnu Mas'ud; 'Apabila kamu benar-benar membacanya, niscaya kamu pasti akan menemukannya. Allah subhanahu wata'ala telah berfirman dalam Al Qur'an: 'Apa yang disampaikan Rasul kepadamu terimalah dan apa yang dilarang untukmu tinggalkanlah.' (Qs. Al Hasyr (59): 7). Wanita itu berkata; 'Aku melihat apa yang kamu bicarakan ada pada istrimu sekarang.' Ibnu Mas'ud menjawab; 'Pergi dan lihatlah ia sekarang! ' Lalu wanita itu pergi ke rumah 'Abdullah bin Mas'ud untuk menemui istrinya. Namun, ia tidak melihat sesuatu pun pada dirinya. Akhirnya ia pergi menemui Ibnu Mas'ud dan berkata; 'Benar, aku memang tidak melihat sesuatu pun pada diri istrimu.' Ibnu Mas'ud pun berkata; 'Ketahuilah, jika ia melakukan hal apa yang aku katakan itu, tentunya aku tidak akan menggaulinya lagi.' Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] keduanya; Telah menceritakan kepada kami ['Abdur Rahman] yaitu Ibnu Mahdi; Telah menceritakan kepada kami [Sufyan]; Demikian juga telah diriwayatkan dari jalur yang lain; Dan telah menceritakan kepada kami [Muhammad bin Rafi']; Telah menceritakan kepada kami [Yahya bin Adam]; Telah menceritakan kepada kami [Mufadhdhal] yaitu Ibnu Muhalhil keduanya dari [Manshur] melalui jalur ini yang semakna dengan Hadits Jarir namun di dalam Hadits Sufyan menggunakan lafazh 'Al Waasyimat wal Mustausyimat. Sedangkan di dalam Hadits Mufadhdhal dengan lafazh; 'Al Wasyimaat wal Mausyumaat. Dan telah menceritakannya kepada kami [Abu Bakr bin Abu Syaibah], [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] mereka berkata; Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Manshur] melalui jalur Hadits ini (kisah yang menyebutkan Ummu Ya'qub semuanya) dari Nabi shallallahu 'alaihi wasallam semata. Dan telah menceritakan kepada kami [Syaiban bin Farukh] Telah menceritakan kepada kami [Jarir] yaitu Ibnu Hazm Telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Qamah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa."},{"p":"Nasa'i","n":5278,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ حَيَّانَ سَمِعَ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ أَنَّهُ سَمِعَ ابْنَ عُمَرَ وَابْنَ عَبَّاسٍأَنَّهُمَا شَهِدَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ ثُمَّ تَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الْآيَةَ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }","trj":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Yazid bin Harun] ia berkata; telah menceritakan kepada kami [Manshur bin Hayyan] ia mendengar [Sa'id bin Jubair] menceritakan bahwasanya ia mendengar [Ibnu Umar] dan [Ibnu Abbas] bersaksi atas Rasulullah shallallahu 'alaihi wasallam, bahwa beliau melarang dari Ad Duba, Al Hantam, Al Muzaffat dan An Naqir. Kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat berikut ini: '(Apa yang diberikan Rasul kepadamu maka terimalah dia. Dan apa yang dilarangnya bagimu maka tinggalkanlah..) ' (Qs. Al Hasyr: 7).\" "},{"p":"Nasa'i","n":5279,"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ عَنْ ابْنِ عَمٍّ لَهَا يُقَالُ لَهُ أَنَسٌ قَالَ قَالَ ابْنُ عَبَّاسٍأَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ مَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قُلْتُ بَلَى قَالَ أَلَمْ يَقُلْ اللَّهُ{ وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى اللَّهُ وَرَسُولُهُ أَمْرًا أَنْ يَكُونَ لَهُمْ الْخِيَرَةُ مِنْ أَمْرِهِمْ }قُلْتُ بَلَى قَالَ فَإِنِّي أَشْهَدُ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّقِيرِ وَالْمُقَيَّرِ وَالدُّبَّاءِ وَالْحَنْتَمِ","trj":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sulaiman At Taimi] dari [Asma binti Yazid] dari anak pamannya yang dipanggil [Anas] ia berkata; [Ibnu Abbas] berkata, \"Bukankah Allah telah mengatakan: '(Apa yang diberikan Rasul kepadamu maka terimalah dia. Dan apa yang dilarangnya bagimu maka tinggalkanlah..) '? (Qs. Al Hasyr: 7), aku menjawab, \"Benar.\" Ibnu Abbas berkata lagi, \"Bukankah Allah telah mengatakan: '(Dan tidaklah patut bagi laki-laki yang Mukmin dan tidak (pula) bagi perempuan yang Mukmin, apabila Allah dan Rasul-Nya telah menetapkan suatu ketetapan, akan ada bagi mereka pilihan (yang lain) tentang urusan mereka..)? (Qs. Al Hasyr: 36), aku menjawab, \"Benar.\" Ibnu Abbas lantas berkata, \"Sesungguhnya aku bersaksi bahwa Nabi Allah shallallahu 'alaihi wasallam melarang An Naqir, Al Muqayyar, Ad Duba dan Al Hantam.\" "}],"59:9":[{"p":"Bukhari","n":3360,"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ فُضَيْلِ بْنِ غَزْوَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ إِلَى نِسَائِهِ فَقُلْنَ مَا مَعَنَا إِلَّا الْمَاءُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَضُمُّ أَوْ يُضِيفُ هَذَا فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ أَنَا فَانْطَلَقَ بِهِ إِلَى امْرَأَتِهِ فَقَالَ أَكْرِمِي ضَيْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ مَا عِنْدَنَا إِلَّا قُوتُ صِبْيَانِي فَقَالَ هَيِّئِي طَعَامَكِ وَأَصْبِحِي سِرَاجَكِ وَنَوِّمِي صِبْيَانَكِ إِذَا أَرَادُوا عَشَاءً فَهَيَّأَتْ طَعَامَهَا وَأَصْبَحَتْ سِرَاجَهَا وَنَوَّمَتْ صِبْيَانَهَا ثُمَّ قَامَتْ كَأَنَّهَا تُصْلِحُ سِرَاجَهَا فَأَطْفَأَتْهُ فَجَعَلَا يُرِيَانِهِ أَنَّهُمَا يَأْكُلَانِ فَبَاتَا طَاوِيَيْنِ فَلَمَّا أَصْبَحَ غَدَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِكَ اللَّهُ اللَّيْلَةَ أَوْ عَجِبَ مِنْ فَعَالِكُمَا فَأَنْزَلَ اللَّهُ{ وَيُؤْثِرُونَ عَلَى أَنْفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ وَمَنْ يُوقَ شُحَّ نَفْسِهِ فَأُولَئِكَ هُمْ الْمُفْلِحُونَ }","trj":"Telah bercerita kepada kami [Musaddad] telah bercerita kepada kami ['Abdullah bin Daud] dari [Fudlail bin Ghazwan] dari [Abu Hazim] dari [Abu Hurairah radliallahu 'anhu] bahwa ada seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam lalu beliau datangi istri-istri beliau. Para istri beliau berkata; \"Kami tidak punya apa-apa selain air\". Maka kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepada orang banyak: \"Siapakah yang mau mengajak atau menjamu orang ini?\". Maka seorang laki-laki dari Anshar berkata; \"Aku\". Sahabat Anshar itu pulang bersama laki-laki tadi menemui istrinya lalu berkata; \"Muliakanlah tamu Rasulullah shallallahu 'alaihi wasallam ini\". Istrinya berkata; \"Kita tidak memiliki apa-apa kecuali sepotong roti untuk anakku\". Sahabat Anshar itu berkata; Suguhkanlah makanan kamu itu lalu matikanlah lampu dan tidurkanlah anakmu\". Ketika mereka hendak menikmati makan malam, maka istrinya menyuguhkan makanan itu lalu mematikan lampu dan menidurkan anaknya kemudian dia berdiri seakan hendak memperbaiki lampunya, lalu dimatikannya kembali. Suami- istri hanya menggerak-gerakkan mulutnya (seperti mengunyah sesuatu) seolah keduanya ikut menikmati hidangan. Kemudian keduanya tidur dalam keadaan lapar karena tidak makan malam. Ketika pagi harinya, pasangan suami istri itu menemui Rasulullah shallallahu 'alaihi wasallam. Maka beliau berkata: \"Malam ini Allah tertawa atau terkagum-kagum karena perbuatan kalian berdua\". Maka kemudian Allah menurunkan firman-Nya dalam QS al-Hasyr ayat 9 yang artinya: (\"Dan mereka lebih mengutamakan orang lain (Muhajirin) dari pada diri mereka sendiri sekalipun mereka memerlukan apa yang mereka berikan itu. Dan siapa yang dipelihara dari kekikiran dirinya, mereka itulah orang-orang yang beruntung\")."},{"p":"Bukhari","n":4205,"ar":"حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ كَثِيرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا فُضَيْلُ بْنُ غَزْوَانَ حَدَّثَنَا أَبُو حَازِمٍ الْأَشْجَعِيُّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَصَابَنِي الْجَهْدُ فَأَرْسَلَ إِلَى نِسَائِهِ فَلَمْ يَجِدْ عِنْدَهُنَّ شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا رَجُلٌ يُضَيِّفُهُ هَذِهِ اللَّيْلَةَ يَرْحَمُهُ اللَّهُ فَقَامَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ أَنَا يَا رَسُولَ اللَّهِ فَذَهَبَ إِلَى أَهْلِهِ فَقَالَ لِامْرَأَتِهِ ضَيْفُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدَّخِرِيهِ شَيْئًا قَالَتْ وَاللَّهِ مَا عِنْدِي إِلَّا قُوتُ الصِّبْيَةِ قَالَ فَإِذَا أَرَادَ الصِّبْيَةُ الْعَشَاءَ فَنَوِّمِيهِمْ وَتَعَالَيْ فَأَطْفِئِي السِّرَاجَ وَنَطْوِي بُطُونَنَا اللَّيْلَةَ فَفَعَلَتْ ثُمَّ غَدَا الرَّجُلُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَقَدْ عَجِبَ اللَّهُ عَزَّ وَجَلَّ أَوْ ضَحِكَ مِنْ فُلَانٍ وَفُلَانَةَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيُؤْثِرُونَ عَلَى أَنْفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ }","trj":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim bin Katsir] Telah menceritakan kepada kami [Abu Usamah] Telah menceritakan kepada kami [Fudlail bin Ghazwan] Telah menceritakan kepada kami [Abu Hazim Al Asyja'i] dari [Abu Hurairah radliallahu 'anhu] ia berkata; Seorang laki-laki mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sungguh, aku mengalami kesulitan (tidak mendapatkan makanan).\" Maka beliau pun mengutus seseorang kepada isteri-isterinya, namun ternyata utusan itu tidak mendapatkan (sesuatu makanan pun). Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah ada seorang pun yang mau menjamunya untuk malam hari ini, semoga Allah merahmatinya.\" Kemudian berdirilah seorang laki-laki dari kalangan Anshar seraya berkata, \"Aku wahai Rasulullah.\" Lalu laki-laki itu pun pergi menemui keluarganya dan berkata kepada isterinya, \"Ini adalah tamu Rasulullah shallallahu 'alaihi wasallam, janganlah kamu mengecewakannya barang sedikit pun.\" Sang isteri pun berkata, \"Demi Allah, aku tidak lagi memiliki apa-apa kecuali makanan untuk anak kita yang kecil.\" Laki-laki itu berkata, \"Jika anak-anak ingin makan malam, maka tidurkanlah mereka. Lalu kemarilah dan matikanlah lampu, kemudian kita berpura-pura menyantap makanan.\" Akhirnya sang isteri pun melakukannya. Pada keesokan harinya, laki-laki itu pun menemui Rasulullah shallallahu 'alaihi wasallam, dan beliau pun bersabda: \"Sungguh, Allah merasa ta'ajjub atau tertawa lantaran apa yang dilakukan si Fulan dan si Fulanah.\" Sehinngga Allah 'azza wajalla pun menurunkan ayat, \"Dan mereka lebih mementingkan yang lain, meskipun mereka sendiri sangat kesusahan.\" (QS. Alhasyr 9)."},{"p":"Tirmidzi","n":3055,"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ فُضَيْلِ بْنِ غَزْوَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا مِنْ الْأَنْصَارِ بَاتَ بِهِ ضَيْفٌ فَلَمْ يَكُنْ عِنْدَهُ إِلَّا قُوتُهُ وَقُوتُ صِبْيَانِهِ فَقَالَ لِامْرَأَتِهِ نَوِّمِي الصِّبْيَةَ وَأَطْفِئِي السِّرَاجَ وَقَرِّبِي لِلضَّيْفِ مَا عِنْدَكِ فَنَزَلَتْ هَذِهِ الْآيَةَ{ وَيُؤْثِرُونَ عَلَى أَنْفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ }هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Fudhail bin Ghazwan] dari [Abu Hazim] dari [Abu Hurairah] bahwa seorang laki-laki dari kalangan anshar bermalam dengan kedatangan seorang tamu sementara ia tidak memiliki makanan kecuali makanan untuk anak-anaknya. Kemudian ia berkata kepada isterinya; tidurkan anak-anak tersebut, dan matikan lampu serta hidangkan apa yang engkau miliki kepada tamu tersebut. Kemudian turunlah ayat ini: \"Dan mereka mengutamakan (orang-orang Muhajirin), atas diri mereka sendiri, sekalipun mereka dalam kesusahan.\" (QS. Alhasyr ayat 9), hadits ini adalah hadits hasan shahih."}],"59:18":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}]},"mapping_surah":[{"p":"Abu Dawud","n":3524,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ قَالَ مُحَمَّدٌ وَالْوَاصِلَاتِ و قَالَ عُثْمَانُ وَالْمُتَنَمِّصَاتِ ثُمَّ اتَّفَقَا وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ عَزَّ وَجَلَّ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ زَادَ عُثْمَانُ كَانَتْ تَقْرَأُ الْقُرْآنَ ثُمَّ اتَّفَقَا فَأَتَتْهُ فَقَالَتْ بَلَغَنِي عَنْكَ أَنَّكَ لَعَنْتَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ قَالَ مُحَمَّدٌ وَالْوَاصِلَاتِ و قَالَ عُثْمَانُ وَالْمُتَنَمِّصَاتِ ثُمَّ اتَّفَقَا وَالْمُتَفَلِّجَاتِ قَالَ عُثْمَانُ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ تَعَالَى فَقَالَ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ تَعَالَى قَالَتْ لَقَدْ قَرَأْتُ مَا بَيْنَ لَوْحَيْ الْمُصْحَفِ فَمَا وَجَدْتُهُ فَقَالَ وَاللَّهِ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ ثُمَّ قَرَأَ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قَالَتْ إِنِّي أَرَى بَعْضَ هَذَا عَلَى امْرَأَتِكَ قَالَ فَادْخُلِي فَانْظُرِي فَدَخَلَتْ ثُمَّ خَرَجَتْ فَقَالَ مَا رَأَيْتِو قَالَ عُثْمَانُ فَقَالَتْ مَا رَأَيْتُ فَقَالَ لَوْ كَانَ ذَلِكَ مَا كَانَتْ مَعَنَا","trj":"Telah menceritakan kepada kami [Muhammad bin Isa] dan [Utsman bin Abu Syaibah] secara makna, keduanya berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Allah melaknat wanita yang mentato dan wanita yang minta untuk ditato.\" Muhammad menyebutkan, \"dan wanita yang meyambung rambut.\" Utsman menyebutkan, \"dan wanita yang mencukur bulu alis.\" Dan keduanya sepakat dengan penyebutan, \"dan mengikir gigi untuk kecantikan dengan merubah ciptaan Allah Azza Wa Jalla. Hadits ini kemudian di dengar oleh seorang wanita dari bani Asad yang biasa di panggil dengan nama Ummu Ya'qub, Utsman menambahkan, \"yang sedang membaca Al-Qur'an. Ia lalu mendatangi Abdullah dan berkata, \"Telah sampai kabar kepadaku bahwa engkau melaknat Wanita yang mentato dan wanita yang minta untuk ditato?\" Muhammad menyebutkan, \"dan wanita yang menyambung rambut.\" Utsman menyebutkan, \"dan wanita yang mencukur alis. Kemudian keduanya sepakat dengan penyebutan, \"wanita yang mengikir gigi, Utsman menyebutkan, \"untuk kecantikan dengan merubah ciptaan Allah Ta'ala.\" Ummu Ya'qub berkata, \"Aku telah membaca lembaran-lembaran Al-Qur'an tetapi aku tidak mendapatkannya.\" Abdullah berkata, \"Demi Allah, jika engkau membacanya, sungguh engkau pasti mendapatkannya.\" Kemudian Abdullah membaca: (Apa yang diberikan Rasul kepadamu maka terimalah dia, dan apa yang dilarangnya bagimu maka tinggalkanlah.. (Qs. Al Hasyr: 7).\" Ummu Ya'qub berkata, \"Aku melihat hal ini ada pada isterimu!\" Abdullah berkata, \"Masuk dan lihatlah.\" Ummu Ya'qub kemudian masuk dan keluar lagi. Abdullah berkata, \"Apa yang engkau lihat?\" Utsman berkata (dalam riwayatnya) maka Ummu Ya'qub berkata; \"Aku tidak melihatnya\", Ibnu Mas'ud berkata; \"Jikalau hal itu ada pada istriku niscaya dia tidak akan ada bersama kami.\""},{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""},{"p":"Bukhari","n":2863,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مُحَمَّدٍ الْفَرْوِيُّ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرٍ ذَكَرَ لِي ذِكْرًا مِنْ حَدِيثِهِ ذَلِكَ فَانْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى مَالِكِ بْنِ أَوْسٍ فَسَأَلْتُهُ عَنْ ذَلِكَ الْحَدِيثِ فَقَالَ مَالِكٌبَيْنَا أَنَا جَالِسٌ فِي أَهْلِي حِينَ مَتَعَ النَّهَارُ إِذَا رَسُولُ عُمَرَ بْنِ الْخَطَّابِ يَأْتِينِي فَقَالَ أَجِبْ أَمِيرَ الْمُؤْمِنِينَ فَانْطَلَقْتُ مَعَهُ حَتَّى أَدْخُلَ عَلَى عُمَرَ فَإِذَا هُوَ جَالِسٌ عَلَى رِمَالِ سَرِيرٍ لَيْسَ بَيْنَهُ وَبَيْنَهُ فِرَاشٌ مُتَّكِئٌ عَلَى وِسَادَةٍ مِنْ أَدَمٍ فَسَلَّمْتُ عَلَيْهِ ثُمَّ جَلَسْتُ فَقَالَ يَا مَالِ إِنَّهُ قَدِمَ عَلَيْنَا مِنْ قَوْمِكَ أَهْلُ أَبْيَاتٍ وَقَدْ أَمَرْتُ فِيهِمْ بِرَضْخٍ فَاقْبِضْهُ فَاقْسِمْهُ بَيْنَهُمْ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ لَوْ أَمَرْتَ بِهِ غَيْرِي قَالَ اقْبِضْهُ أَيُّهَا الْمَرْءُ فَبَيْنَا أَنَا جَالِسٌ عِنْدَهُ أَتَاهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَالزُّبَيْرِ وَسَعْدِ بْنِ أَبِي وَقَّاصٍ يَسْتَأْذِنُونَ قَالَ نَعَمْ فَأَذِنَ لَهُمْ فَدَخَلُوا فَسَلَّمُوا وَجَلَسُوا ثُمَّ جَلَسَ يَرْفَا يَسِيرًا ثُمَّ قَالَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ قَالَ نَعَمْ فَأَذِنَ لَهُمَا فَدَخَلَا فَسَلَّمَا فَجَلَسَا فَقَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا وَهُمَا يَخْتَصِمَانِ فِيمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَالِ بَنِي النَّضِيرِ فَقَالَ الرَّهْطُ عُثْمَانُ وَأَصْحَابُهُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ قَالَ عُمَرُ تَيْدَكُمْ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُ قَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا اللَّهَ أَتَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ ذَلِكَ قَالَا قَدْ قَالَ ذَلِكَ قَالَ عُمَرُ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ قَدْ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْفَيْءِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ ثُمَّ قَرَأَ{ وَمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ قَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ ذَلِكَ قَالَ عُمَرُ ثُمَّ تَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهَا أَبُو بَكْرٍ فَعَمِلَ فِيهَا بِمَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ يَعْلَمُ إِنَّهُ فِيهَا لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَكُنْتُ أَنَا وَلِيَّ أَبِي بَكْرٍ فَقَبَضْتُهَا سَنَتَيْنِ مِنْ إِمَارَتِي أَعْمَلُ فِيهَا بِمَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا عَمِلَ فِيهَا أَبُو بَكْرٍ وَاللَّهُ يَعْلَمُ إِنِّي فِيهَا لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ جِئْتُمَانِي تُكَلِّمَانِي وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا وَاحِدٌ جِئْتَنِي يَا عَبَّاسُ تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكَ وَجَاءَنِي هَذَا يُرِيدُ عَلِيًّا يُرِيدُ نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ لَكُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ فَلَمَّا بَدَا لِي أَنْ أَدْفَعَهُ إِلَيْكُمَا قُلْتُ إِنْ شِئْتُمَا دَفَعْتُهَا إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهَا بِمَا عَمِلَ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِمَا عَمِلَ فِيهَا أَبُو بَكْرٍ وَبِمَا عَمِلْتُ فِيهَا مُنْذُ وَلِيتُهَا فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا فَبِذَلِكَ دَفَعْتُهَا إِلَيْكُمَا فَأَنْشُدُكُمْ بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْهِمَا بِذَلِكَ قَالَ الرَّهْطُ نَعَمْ ثُمَّ أَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ قَالَا نَعَمْ قَالَ فَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ فَإِنْ عَجَزْتُمَا عَنْهَا فَادْفَعَاهَا إِلَيَّ فَإِنِّي أَكْفِيكُمَاهَا","trj":"Telah bercerita kepada kami [Ishaq bin Muhammad Al Farwiy] telah bercerita kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Malik bin Aus Al Hadatsan], bahwa [Muhammad bin Jubair] menyebutkan kepadaku suatu cerita dari hadits yang disampaikannya maka aku berangkat menemui Malik bin Aus lalu aku bertanya kepadanya tentang hadits yang dimaksud, maka Malik berkata; \"Ketika aku sedang duduk bersama keluargaku di tengah hari tiba-tiba datang utusan 'Umar bin Al Khaththab menemuiku lalu berkata; \"Penuhilah panggilan Amirul Mu'minin\". Maka aku pergi bersamanya menemui ['Umar] yang ketika itu sedang duduk di atas tikar yang tidak dialasi kasur namun bersandar pada bantal terbuat dari kulit. Aku memberi salam kepadanya lalu duduk. Maka dia berkata; \"Wahai Maal (Malik), sesungguhnya telah datang kepada kami para ahli bait dari kaummu dan aku sudah memerintahkan untuk memberi mereka pemberian yang sedikit dan tidak bernilai, maka terimalah ini dan bagikanlah kepada mereka\". Aku berkata; \"Wahai Amirul Mu'minin, andai engkau perintahkan hal ini kepada selain aku\". Dia berkata; \"Terimalah, hai laki-laki\". Di tengah aku sedang duduk bersamanya, datang kepadanya penjaga pintu yang bernama Yarfaa lalu berkata; \"Apakah kamu membolehkan ['Utsman], ['Abdur Rahman bin 'Auf], [Az Zubair] dan [Sa'ad bin Abi Waqash], mereka minta izin masuk\". 'Umar menjawab; \"Ya\". Lalu dia mengizinkan mereka masuk. Maka mereka masuk dan memberi salam lalu duduk. Begitu juga Yarfaa duduk sebentar lalu berkata; \"Apakah kamu juga membolehkan ['Ali] dan ['Abbas] masuk?\". 'Umar menjawab; \"Ya\". Lalu 'Umar mengizinkan keduanya masuk. Keduanya pun masuk dan memberi salam lalu duduk. 'Abbas berkata; \"Wahai Amirul Mu'minin, putuskanlah antara aku dan orang ini\". Keduanya sedang bertengkar urusan harta yang Allah karuniakan kepada Rasulullah Shallallahu'alaiwasallam berupa fa'i dari harta Bani an-Nadlir. Kelompok orang yang bersama 'Utsman dan para shohabatnya berkata; \"Wahai Amirul Mu'minin, putuskanlah perkara mereka berdua dan legakanlah salah seorang diantara keduanya\". 'Umar berkata; \"Tenanglah kalian!. Dan aku aku minta kepada kalian, demi Allah yang dengan izin-Nya tegak langit dan bumi, apakah kalian mengetahui bahwa Rasulullah Shallallahu'alaiwasallam telah bersabda: \"Kami tidak mewariskan, Apa-apa yang kami tinggalkan menjadi shadaqah?\". Yang Rasulullah Shallallahu'alaiwasallam maksudkan (dengan kata kami) adalah diri Beliau sendiri. Kelompok ('Utsman) berkata; \"Ya, Beliau sudah bersabda demikian\". Maka 'Umar kembali menghadap dan berbicara kepada 'Ali dan 'Abbas; \"Aku minta kepada kalian berdua, demi Allah, apakah kalian berdua mengetahui bahwa Rasulullah Shallallahu'alaiwasallam telah bersabda seperti itu?\". Keduanya menjawab; \"Ya, Beliau sudah bersabda demikian\". 'Umar kemudian berkata; \"Untuk itu aku akan berbicara kepada kalian tentang masalah ini. Sesungguhnya Allah tekah mengkhusukan Rasul-Nya Shallallahu'alaihiwasallam dalam masalah fa'i ini sebagai sesuatu yang tidak Dia berikan kepada siapapun selain Beliau Shallallahu'alaihiwasallam\". Lalu 'Umar membaca firman Allah (QS Al Hasyr ayat 6 yang artinya: (\"Dan apa saja yang dikaruniakan Allah berupa fa'i (rampasan perang) kepada Rasul-Nya dari (harta benda) mereka…) hingga firman-Nya (dan Allah Maha berkuasa atas segala sesuatu\"), ayat ini merupakan kekhususan buat Rasulullah Shallallahu'alaiwasallam. Demi Allah, tidaklah Beliau mengumpulkannya dengan mengabaikan kalian dan juga tidak untuk lebih mementingkan kalian. Sungguh Beliau telah memberikannya kepada kalian dan menyebarkannya di tengah-tengah kalian (kaum Muslimin) dan hingga sekarang masih ada yang tersisa dari harta tersebut. Dan Rasulullah Shallallahu'alaiwasallam telah memberi nafkah belanja kepada keluarga Beliau sebagai nafkah tahunan mereka dari harta fa'i ini lalu sisanya Beliau ambil dan dijadikannya sebagai harta Allah dan Beliau sudah menerapkan semua ini selama hidup Beliau. Aku tanya kepda kalian, bukankah kalian sudah mengetahui ini semua?\". Mereka menjawab; \"Ya. Lalu 'Umar berbicara kepada 'Ali dan 'Abbas; \"Aku tanya kepada kalian berdua, bukankah kamu berdua sudah mengetahui ini semua?\". 'Umar melanjutkan; \"Kemudian Allah mewafatkan Nabi-Nya Shallallahu'alaihiwasallam, kemudian Abu Bakr berkata; \"Akulah wali Rasulullah Shallallahu'alaiwasallam. Lalu Abu Bakr menjadi yang memegang kepemimpinan, maka dia melaksanakan seperti apa yang dilaksanakan oleh Rasulullah Shallallahu'alaiwasallam dan apa yang telah dilakukan oleh Abu Bakr, sungguh Allah mengetahuinya, bahwa aku dalam perkara ini berpendapat bahwa dia orang yang jujur, bijak, lurus dan pengikut kebenaran. Lalu kalian berdua datang kepadaku dan berbicara kepadaku, sedang ucapan kalian satu dan maksud urusan kalian juga satu. Engkau, wahai 'Abbas, datang kepadaku meminta kepadaku bagian dari anak saudara kamu. Dan orang ini, yang 'Umar maksud adalah 'Ali, datang meminta bagian istrinya dari ayahnya. Aku katakan kepada kalian berdua, sesungguhnya Rasulullah Shallallahu'alaiwasallam telah bersabda: \"Kami tidak mewariskan. Apa-apa yang kami tinggalkan menjadi shadaqah\". Setelah jelas bagiku bahwa aku harus memberikannya kepada kalian berdua maka aku akan katakan, jika memang kalian menghendakinya aku akan berikan kepada kalian berdua namun wajib kalian berdua ingat janji Allah dan ketentuan-Nya bahwa kalian sungguh mengetahui tentang urusan ini apa yang telah Rasulullah Shallallahu'alaiwasallam lakukan dan apa yang telah Abu Bakr lakukan, dan juga apa yang telah aku lakukan sejak aku memegang kekuasaan ini dan jika kalian berdua mengatakan berikanlah kepada kami, maka dengan ketentuan seperti itu aku akan berikan kepada kalian berdua. Dan aku ingatkan kepada kalian semua, demi Allah, apakah aku berikan kepada keduanya dengan ketentuan seperti ini. Kelompok 'Utsman berkata; \"Ya\". Kemudian 'Umar menghadap 'Ali dan 'Abbas seraya berkata; \"Aku ingatkan kalian berdua, demi Allah, apakah aku memberikannya kepada kalian berdua berdasarkan ketentuan ini?\". Keduanya menjawab; \"Ya\". 'Selanjutnya 'Umar berkata; \"Lalu kalian menghampiri aku agar aku memutuskan perkara ini dengan ketentuan lain. Sungguh demi Allah yang dengan izin-Nya tegaklah langit dan bumi, aku tidak akan pernah memutuskan masalah ini dengan selain ketentuan ini. Seandainya kalian berdua tidak sanggup atasnya maka serahkanlah kepadaku karena sungguh aku akan mengganti kalian untuk mengurus harta itu.\""},{"p":"Bukhari","n":3360,"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ فُضَيْلِ بْنِ غَزْوَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ إِلَى نِسَائِهِ فَقُلْنَ مَا مَعَنَا إِلَّا الْمَاءُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَضُمُّ أَوْ يُضِيفُ هَذَا فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ أَنَا فَانْطَلَقَ بِهِ إِلَى امْرَأَتِهِ فَقَالَ أَكْرِمِي ضَيْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ مَا عِنْدَنَا إِلَّا قُوتُ صِبْيَانِي فَقَالَ هَيِّئِي طَعَامَكِ وَأَصْبِحِي سِرَاجَكِ وَنَوِّمِي صِبْيَانَكِ إِذَا أَرَادُوا عَشَاءً فَهَيَّأَتْ طَعَامَهَا وَأَصْبَحَتْ سِرَاجَهَا وَنَوَّمَتْ صِبْيَانَهَا ثُمَّ قَامَتْ كَأَنَّهَا تُصْلِحُ سِرَاجَهَا فَأَطْفَأَتْهُ فَجَعَلَا يُرِيَانِهِ أَنَّهُمَا يَأْكُلَانِ فَبَاتَا طَاوِيَيْنِ فَلَمَّا أَصْبَحَ غَدَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِكَ اللَّهُ اللَّيْلَةَ أَوْ عَجِبَ مِنْ فَعَالِكُمَا فَأَنْزَلَ اللَّهُ{ وَيُؤْثِرُونَ عَلَى أَنْفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ وَمَنْ يُوقَ شُحَّ نَفْسِهِ فَأُولَئِكَ هُمْ الْمُفْلِحُونَ }","trj":"Telah bercerita kepada kami [Musaddad] telah bercerita kepada kami ['Abdullah bin Daud] dari [Fudlail bin Ghazwan] dari [Abu Hazim] dari [Abu Hurairah radliallahu 'anhu] bahwa ada seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam lalu beliau datangi istri-istri beliau. Para istri beliau berkata; \"Kami tidak punya apa-apa selain air\". Maka kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepada orang banyak: \"Siapakah yang mau mengajak atau menjamu orang ini?\". Maka seorang laki-laki dari Anshar berkata; \"Aku\". Sahabat Anshar itu pulang bersama laki-laki tadi menemui istrinya lalu berkata; \"Muliakanlah tamu Rasulullah shallallahu 'alaihi wasallam ini\". Istrinya berkata; \"Kita tidak memiliki apa-apa kecuali sepotong roti untuk anakku\". Sahabat Anshar itu berkata; Suguhkanlah makanan kamu itu lalu matikanlah lampu dan tidurkanlah anakmu\". Ketika mereka hendak menikmati makan malam, maka istrinya menyuguhkan makanan itu lalu mematikan lampu dan menidurkan anaknya kemudian dia berdiri seakan hendak memperbaiki lampunya, lalu dimatikannya kembali. Suami- istri hanya menggerak-gerakkan mulutnya (seperti mengunyah sesuatu) seolah keduanya ikut menikmati hidangan. Kemudian keduanya tidur dalam keadaan lapar karena tidak makan malam. Ketika pagi harinya, pasangan suami istri itu menemui Rasulullah shallallahu 'alaihi wasallam. Maka beliau berkata: \"Malam ini Allah tertawa atau terkagum-kagum karena perbuatan kalian berdua\". Maka kemudian Allah menurunkan firman-Nya dalam QS al-Hasyr ayat 9 yang artinya: (\"Dan mereka lebih mengutamakan orang lain (Muhajirin) dari pada diri mereka sendiri sekalipun mereka memerlukan apa yang mereka berikan itu. Dan siapa yang dipelihara dari kekikiran dirinya, mereka itulah orang-orang yang beruntung\")."},{"p":"Bukhari","n":3526,"ar":"حَدَّثَنِي الْحَسَنُ بْنُ مُدْرِكٍ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍسُورَةُ الْحَشْرِ قَالَ قُلْ سُورَةُ النَّضِيرِتَابَعَهُ هُشَيْمٌ عَنْ أَبِي بِشْرٍ","trj":"Telah menceritakan kepadaku [Al Hasan bin Mudrik] telah menceritakan kepada kami [Yahya bin Hammad] telah mengabarkan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dia berkata, aku berkata kepada [Ibnu Abbas] mengenai surat Al Hasyr, dia berkata, \"Katakanlah surat An Nadlir.\" Riwayat ini juga dikuatkan oleh [Husyaim] dari [Abu Bisyr]."},{"p":"Bukhari","n":3528,"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَحَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَنَزَلَتْ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Al Laits] dari [An Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah membakar kebun kurma Bani Nadlir dan memotongnya, yaitu yang ada di Buwairah. Kemudian turunlah ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya. Maka (semua itu) adalah dengan izin Allah) ' (Qs. Al Hasyr: 5)."},{"p":"Bukhari","n":3530,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ النَّصْرِيُّ أَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُدَعَاهُ إِذْ جَاءَهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ يَسْتَأْذِنُونَ فَقَالَ نَعَمْ فَأَدْخِلْهُمْ فَلَبِثَ قَلِيلًا ثُمَّ جَاءَ فَقَالَ هَلْ لَكَ فِي عَبَّاسٍ وَعَلِيٍّ يَسْتَأْذِنَانِ قَالَ نَعَمْ فَلَمَّا دَخَلَا قَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا وَهُمَا يَخْتَصِمَانِ فِي الَّذِي أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَنِي النَّضِيرِ فَاسْتَبَّ عَلِيٌّ وَعَبَّاسٌ فَقَالَ الرَّهْطُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ فَقَالَ عُمَرُ اتَّئِدُوا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ بِذَلِكَ نَفْسَهُ قَالُوا قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَبَّاسٍ وَعَلِيٍّ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ ذَلِكَ قَالَا نَعَمْ قَالَ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ سُبْحَانَهُ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْفَيْءِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ فَقَالَ جَلَّ ذِكْرُهُ{ وَمَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَهَا عَلَيْكُمْ لَقَدْ أَعْطَاكُمُوهَا وَقَسَمَهَا فِيكُمْ حَتَّى بَقِيَ هَذَا الْمَالُ مِنْهَا فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيَاتَهُ ثُمَّ تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ فَأَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهُ أَبُو بَكْرٍ فَعَمِلَ فِيهِ بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمْ حِينَئِذٍ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ وَقَالَ تَذْكُرَانِ أَنَّ أَبَا بَكْرٍ فِيهِ كَمَا تَقُولَانِ وَاللَّهُ يَعْلَمُ إِنَّهُ فِيهِ لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ فَقَبَضْتُهُ سَنَتَيْنِ مِنْ إِمَارَتِي أَعْمَلُ فِيهِ بِمَا عَمِلَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَاللَّهُ يَعْلَمُ أَنِّي فِيهِ صَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ جِئْتُمَانِي كِلَاكُمَا وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا جَمِيعٌ فَجِئْتَنِي يَعْنِي عَبَّاسًا فَقُلْتُ لَكُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ فَلَمَّا بَدَا لِي أَنْ أَدْفَعَهُ إِلَيْكُمَا قُلْتُ إِنْ شِئْتُمَا دَفَعْتُهُ إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهِ بِمَا عَمِلَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَمَا عَمِلْتُ فِيهِ مُنْذُ وَلِيتُ وَإِلَّا فَلَا تُكَلِّمَانِي فَقُلْتُمَا ادْفَعْهُ إِلَيْنَا بِذَلِكَ فَدَفَعْتُهُ إِلَيْكُمَا أَفَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهِ بِقَضَاءٍ غَيْرِ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهُ فَادْفَعَا إِلَيَّ فَأَنَا أَكْفِيكُمَاهُقَالَ فَحَدَّثْتُ هَذَا الْحَدِيثَ عُرْوَةَ بْنَ الزُّبَيْرِ فَقَالَ صَدَقَ مَالِكُ بْنُ أَوْسٍ أَنَا سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُ أَرْسَلَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُثْمَانَ إِلَى أَبِي بَكْرٍ يَسْأَلْنَهُ ثُمُنَهُنَّ مِمَّا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ أَنَا أَرُدُّهُنَّ فَقُلْتُ لَهُنَّ أَلَا تَتَّقِينَ اللَّهَ أَلَمْ تَعْلَمْنَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ بِذَلِكَ نَفْسَهُ إِنَّمَا يَأْكُلُ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَالِ فَانْتَهَى أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى مَا أَخْبَرَتْهُنَّ قَالَ فَكَانَتْ هَذِهِ الصَّدَقَةُ بِيَدِ عَلِيٍّ مَنَعَهَا عَلِيٌّ عَبَّاسًا فَغَلَبَهُ عَلَيْهَا ثُمَّ كَانَ بِيَدِ حَسَنِ بْنِ عَلِيٍّ ثُمَّ بِيَدِ حُسَيْنِ بْنِ عَلِيٍّ ثُمَّ بِيَدِ عَلِيِّ بْنِ حُسَيْنٍ وَحَسَنِ بْنِ حَسَنٍ كِلَاهُمَا كَانَا يَتَدَاوَلَانِهَا ثُمَّ بِيَدِ زَيْدِ بْنِ حَسَنٍ وَهِيَ صَدَقَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقًّا","trj":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata, telah mengabarkan kepadaku [Malik bin Aus bin Al Hadatsan] bahwa [Umar bin Al Khattab] radliallahu 'anhu pernah memanggilnya, setelah itu penjaga pintunya, Yarfa, datang melapor, \"Apakah anda mengizinkan [Utsman], [Abdurrahman], [Zubair] dan [Sa'd] untuk masuk?\" Umar menjawab, \"Ya.\" Kemudian penjaga pintu menyuruh mereka masuk, tidak lama kemudian penjaga pintu datang lagi dan berkata, 'Apakah anda mengizinkan [Abbas] dan [Ali] untuk masuk?\" Umar menjawab, \"Ya.\" Ketika keduanya telah masuk, Abbas berkata, \"Wahai Amirul Mukminin, putuskanlah antara kami dengan orang ini.\" Ketika itu mereka tengah berselisih masalah harta yang Allah karuniakan kepada Rasul-Nya shallallahu 'alaihi wasallam, yakni berupa harta milik Bani Nadlir hingga keduanya saling mencela. Sebagian kelompok berkata, \"Wahai Amirul mukminin, buatlah keputusan untuk keduanya, dan legakanlah salah seorang di antara keduanya.\" 'Umar pun berkata, \"Tenanglah kalian! Dan aku minta kepada kalian, demi Allah yang dengan izin-Nya langit dan bumi tegak, apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak mewariskan. Dan apa-apa yang kami tinggalkan menjadi sedekah.\" Yang beliau maksudkan (dengan kata kami) adalah diri beliau sendiri. Mereka menjawab, \"Ya, beliau telah bersabda demikian.\" Maka 'Umar kembali menghadap dan berbicara kepada 'Ali dan 'Abbas, \"Aku minta kepada kalian berdua, demi Allah, apakah kalian berdua mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda seperti itu?\" Keduanya menjawab, \"Ya, beliau telah bersabda seperti itu.\" Umar kemudian melanjutkan, \"Untuk itu aku akan menyampaikan kepada kalian tentang masalah ini. Sesungguhnya Allah telah mengkhususkan Rasul-Nya shallallahu 'alaihi wasallam dalam masalah fa'i ini sebagai sesuatu yang tidak Dia berikan kepada siapapun selain beliau.\" Lalu Umar membaca firman Allah: '(Dan apa saja yang dikaruniakan Allah berupa fa'i (rampasan perang) kepada Rasul-Nya dari (harta benda) mereka… -hingga firmanNya- dan Allah Maha berkuasa atas segala sesuatu) ' (Qs. Al Hasyr: 6), ayat ini merupakan pengkhususan untuk Rasulullah shallallahu 'alaihi wasallam. Demi Allah, tidaklah beliau mengumpulkannya dengan tidak memperhatikan kalian dan juga tidak untuk lebih mementingkan diri kalian. Sungguh, beliau telah memberikannya kepada kalian dan menyebarkannya di tengah-tengah kalian (kaum Muslimin) hingga sekarang masih ada yang tersisa dari harta tersebut. Dan Rasulullah shallallahu 'alaihi wasallam telah memberi nafkah belanja kepada keluarga beliau sebagai nafkah tahunan mereka dari harta fa'i ini, lalu sisanya beliau ambil dan dijadikannya sebagai harta Allah, beliau sudah menerapkan semua ini samasa hidup beliau. Kemudian Nabi shallallahu 'alaihi wasallam wafat, lalu Abu Bakr berkata, 'Akulah wali Rasulullah shallallahu 'alaihi wasallam.' Maka Abu Bakr pun mewenangi harta itu, kemudian ia mengelolanya seperti apa yang dilaksanakan oleh Rasulullah shallallahu 'alaihi wasallam, saat itu kalian juga ada.\" Kemudian Umar menghadap ke arah arah Ali dan Abbas, dia berkata, \"Kalian berdua juga ingat bahwa dalam mengelola harta itu sebagaimana yang kalian berdua katakan, sungguh Allah juga Maha tahu, bahwa dia adalah orang yang jujur, bijak, lurus dan pengikut kebenaran. Kemudian Allah mewafatkan Abu Bakr, lalu aku berkata, 'Aku adalah pengganti Rasulullah shallallahu 'alaihi wasallam dan Abu Bakr, ' dan aku berwenang untuk mengelola harta tersebut hingga dua tahun dari kepemimpinanku, aku mengelolanya sebagaimana yang dikelola Rasulullah shallallahu 'alaihi wasallam dan Abu Bakr. Dan Allah juga mengetahui bila aku adalah sosok yang jujur, bijak, lurus dan pengikut kebenaran, lalu kenapa kalian datang kepadaku dan berbicara kepadaku padahal ucapan kalian satu dan maksud urusan kalian juga satu. Engkau, wahai 'Abbas, kau datang kepadaku lalu aku katakan kepada kalian berdua, 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak mewariskan. Apa-apa yang kami tinggalkan menjadi sedekah.\" Setelah jelas bagiku bahwa aku harus memberikannya kepada kalian berdua, maka aku akan katakan, Jika memang kalian menghendakinya aku akan berikan kepada kalian berdua, namun kalian berdua harus ingat akan janji Allah dan ketentuan-Nya, yaitu kalian harus mengelola sebagaimana yang pernah dikelola Rasulullah shallallahu 'alaihi wasallam, Abu Bakr lakukan dan juga apa yang telah aku lakukan sejak aku memegang kekuasaan ini, jika tidak, maka kalian jangan mengatakan sesuatu kepadaku, jika kalian berdua mengatakan, \"Berikanlah kepada kami, \" maka dengan ketentuan seperti itu, aku akan berikan kepada kalian berdua. Apakah kalian berdua hendak merubah ketentuan selain dari itu? Demi Allah, yang dengan izin-Nya langit dan bumi bias tegak, aku tidak akan memutuskan dengan keputusan selain itu sampai tiba hari Kiamat, seandainya kalian berdua tidak sanggup atasnya maka serahkanlah kepadaku karena sungguh aku akan mencukupkan kalian berdua dengannya (harta itu).\" Perawi berkata, \"Lalu aku sampaikan hadits ini kepada ['Urwah bin Az Zubair], dia menjawab, \"Malik bin Aus benar, aku juga pernah mendengar ['Aisyah] radliallahu 'anha, isteri Nabi shallallahu 'alaihi wasallam, berkata, \"Para isteri Nabi shallallahu 'alaihi wasallam pernah mengutus Utsman menemui Abu Bakr untuk meminta seperdelapan dari harta yang telah Allah karuniakan kepada Rasul-Nya shallallahu 'alaihi wasallam, lalu aku menolak mereka, aku katakan kepada mereka, \"Apakah kalian tidak takut kepada Allah? Apakah kalian tidak mengetahui bahwa Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi, dan yang kami tinggalkan adalah sedekah -yang beliau maksud dengan (kami) adalah diri beliau sendiri-, sesungguhnya keluarga Muhammad makan dari harta ini.\" Maka para isteri Nabi shallallahu 'alaihi wasallam berhenti pada apa yang telah disampaikan oleh Aisyah kepada mereka.\" Urwah berkata, \"Maka harta sedekah ini ada di tangan Ali, sementara Ali mencegah Abbas dari harta tersebut, dan dapat mengalahkannya, kemudian beralih ditangan Hasan bin Ali, kemudian berpindah ketangan Husain bin Ali, kemudian berpindah ke tangan Ali bin Husain, kemudian Al Hasan bin Al Hasan, keduanya saling bergantian, kemudian berpindah ke tangan Zaid bin Hasan, dan sesungguhnya itu merupakan sedekah Rasulullah shallallahu 'alaihi wasallam.\""},{"p":"Bukhari","n":4198,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍسُورَةُ التَّوْبَةِ قَالَ التَّوْبَةُ هِيَ الْفَاضِحَةُ مَا زَالَتْ تَنْزِلُ وَمِنْهُمْ وَمِنْهُمْ حَتَّى ظَنُّوا أَنَّهَا لَنْ تُبْقِيَ أَحَدًا مِنْهُمْ إِلَّا ذُكِرَ فِيهَا قَالَ قُلْتُ سُورَةُ الْأَنْفَالِ قَالَ نَزَلَتْ فِي بَدْرٍ قَالَ قُلْتُ سُورَةُ الْحَشْرِ قَالَ نَزَلَتْ فِي بَنِي النَّضِيرِ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah menceritakan kepada kami [Sa'id bin Sulaiman] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] ia berkata; Aku pernah bertanya kepada [Ibnu Abbas] mengenai surat At Taubah, maka ia pun menjelaskan, \"Surat At Taubah adalah diistilahkan Al Fadlihah (yang membongkar kejahatan kaum munafik). Ia senantiasa turun dengan ungkapan, 'WA MINHUM.., WA MINHUM.. (Dan di antara mereka.. dan di antara mereka) ' hingga mereka pun menyangka bahwa tidak ada seorang pun yang tersisa dari mereka kecuali disebutkan dalam surat tersebut.\" Kemudian aku bertanya, \"Bagaimana dengan surat Al Anfal? ' Ia menjelaskan, \"Surat itu turun pada saat terjadinya perang Badar.\" Aku bertanya lagi, \"Kalau surat Al Hasyr?\" Ia pun menjelaskan, \"Surat itu turun berkenaan dengan Bani Nadlir.\""},{"p":"Bukhari","n":4199,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُدْرِكٍ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاسُورَةُ الْحَشْرِ قَالَ قُلْ سُورَةُ النَّضِيرِ","trj":"Telah menceritakan kepada kami [Al Hasan bin Mudrik] Telah menceritakan kepada kami [Yahya bin Hammad] Telah mengabarkan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id] ia berkta; Aku pernah bertanya kepada [Ibnu Abbas] mengenai surat Al Hasyr, maka ia pun menjawab, \"Surat itu adalah surat An Nadlir (surat yang turun berkenaan dengan Bani Nadlir).\""},{"p":"Bukhari","n":4200,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ تَعَالَى{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }","trj":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, bahwasanya Rasulullah shallallahu 'alaihi wasallam membakar pepohonan kurma Bani Nadlir dan juga memotongnya, yakni Al Buwairah, maka Allah Ta'ala pun menurunkan ayat, \"Pepohonan (kurma) yang telah kalian tebang atau yang kalian biarkan berdiri tegak di atas pokoknya adalah atas dasar izin dari Allah, dan untuk menghinakan orang-orang yang fasik.\" (QS. Alhasyr 5)."},{"p":"Bukhari","n":4202,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُوتَشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ فَجَاءَتْ فَقَالَتْ إِنَّهُ بَلَغَنِي عَنْكَ أَنَّكَ لَعَنْتَ كَيْتَ وَكَيْتَ فَقَالَ وَمَا لِي أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ هُوَ فِي كِتَابِ اللَّهِ فَقَالَتْ لَقَدْ قَرَأْتُ مَا بَيْنَ اللَّوْحَيْنِ فَمَا وَجَدْتُ فِيهِ مَا تَقُولُ قَالَ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ أَمَا قَرَأْتِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قَالَتْ بَلَى قَالَ فَإِنَّهُ قَدْ نَهَى عَنْهُ قَالَتْ فَإِنِّي أَرَى أَهْلَكَ يَفْعَلُونَهُ قَالَ فَاذْهَبِي فَانْظُرِي فَذَهَبَتْ فَنَظَرَتْ فَلَمْ تَرَ مِنْ حَاجَتِهَا شَيْئًا فَقَالَ لَوْ كَانَتْ كَذَلِكَ مَا جَامَعْتُهَا","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata, \"Semoga Allah melaknati Al Wasyimaat (wanita yang mentato) dan Al Mutawatasyimaat (wanita yang meminta untuk ditato), Al Mutanammishaat (wanita yang mencukur alisnya), serta Al Mutafallijaat (merenggangkan gigi) untuk keindahan, yang mereka merubah-rubah ciptaan Allah.\" Kemudian ungkapan itu sampai kepada salah seorang wanita dari Bani Asad yang biasa dipanggil Ummu Ya'qub. Lalu wanita itu pun datang dan berkata, \"Telah sampai kepadaku berita tentang Anda. Bahwa Anda telah melaknat yang ini dan itu.\" Abdullah berkata, \"Mengapakah aku tidak melaknat mereka yang telah dilaknat oleh Rasulullah shallallahu 'alaihi wasallam dan mereka yang terdapat di dalam Kitabullah?.\" Kemudian wanita berkata, \"Sungguh, aku telah membaca di atara kedua lembarannya, namun di dalamnya aku tidaklah mendapatkan apa yang telah Anda katakan.\" Abdullah menjelaskan, \"Sekiranya Anda membacanya secara keseluruhan, maka niscaya saudari akan menemukannya. Bukankah Allah telah berfirman: 'Apa yang dibawa Rasul untuk kalian, maka ambillah, sedangkan apa yang dilarangnya, maka tingalkanlah? '\" (QS. Alhasyr 7). Wanita itu menjawab, \"Ya, benar.\" Abdullah melanjutkan, \"Sesungguhnya beliau telah melarang hal itu.\" Wanita itu kembali berkata, \"Tetapi, sesungguhnya aku menduga kuat, bahwa isteri anda sendiri melakukan hal itu.\" Abdullah berkata, \"Kalau itu anggapanmu, berangkatlah dan lihatlah.\" Lalu wanita itu pun pergi untuk melihatnya, namun ternyata tidak mendapatkan kebenaran dugaannya sedikit pun. Kemudian Abdullah pun berkata, \"Sekiranya isteriku seperti itu, niscaya aku tidak akan mencampurinya.\""},{"p":"Bukhari","n":4205,"ar":"حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ كَثِيرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا فُضَيْلُ بْنُ غَزْوَانَ حَدَّثَنَا أَبُو حَازِمٍ الْأَشْجَعِيُّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَصَابَنِي الْجَهْدُ فَأَرْسَلَ إِلَى نِسَائِهِ فَلَمْ يَجِدْ عِنْدَهُنَّ شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا رَجُلٌ يُضَيِّفُهُ هَذِهِ اللَّيْلَةَ يَرْحَمُهُ اللَّهُ فَقَامَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ أَنَا يَا رَسُولَ اللَّهِ فَذَهَبَ إِلَى أَهْلِهِ فَقَالَ لِامْرَأَتِهِ ضَيْفُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدَّخِرِيهِ شَيْئًا قَالَتْ وَاللَّهِ مَا عِنْدِي إِلَّا قُوتُ الصِّبْيَةِ قَالَ فَإِذَا أَرَادَ الصِّبْيَةُ الْعَشَاءَ فَنَوِّمِيهِمْ وَتَعَالَيْ فَأَطْفِئِي السِّرَاجَ وَنَطْوِي بُطُونَنَا اللَّيْلَةَ فَفَعَلَتْ ثُمَّ غَدَا الرَّجُلُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَقَدْ عَجِبَ اللَّهُ عَزَّ وَجَلَّ أَوْ ضَحِكَ مِنْ فُلَانٍ وَفُلَانَةَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيُؤْثِرُونَ عَلَى أَنْفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ }","trj":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim bin Katsir] Telah menceritakan kepada kami [Abu Usamah] Telah menceritakan kepada kami [Fudlail bin Ghazwan] Telah menceritakan kepada kami [Abu Hazim Al Asyja'i] dari [Abu Hurairah radliallahu 'anhu] ia berkata; Seorang laki-laki mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sungguh, aku mengalami kesulitan (tidak mendapatkan makanan).\" Maka beliau pun mengutus seseorang kepada isteri-isterinya, namun ternyata utusan itu tidak mendapatkan (sesuatu makanan pun). Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah ada seorang pun yang mau menjamunya untuk malam hari ini, semoga Allah merahmatinya.\" Kemudian berdirilah seorang laki-laki dari kalangan Anshar seraya berkata, \"Aku wahai Rasulullah.\" Lalu laki-laki itu pun pergi menemui keluarganya dan berkata kepada isterinya, \"Ini adalah tamu Rasulullah shallallahu 'alaihi wasallam, janganlah kamu mengecewakannya barang sedikit pun.\" Sang isteri pun berkata, \"Demi Allah, aku tidak lagi memiliki apa-apa kecuali makanan untuk anak kita yang kecil.\" Laki-laki itu berkata, \"Jika anak-anak ingin makan malam, maka tidurkanlah mereka. Lalu kemarilah dan matikanlah lampu, kemudian kita berpura-pura menyantap makanan.\" Akhirnya sang isteri pun melakukannya. Pada keesokan harinya, laki-laki itu pun menemui Rasulullah shallallahu 'alaihi wasallam, dan beliau pun bersabda: \"Sungguh, Allah merasa ta'ajjub atau tertawa lantaran apa yang dilakukan si Fulan dan si Fulanah.\" Sehinngga Allah 'azza wajalla pun menurunkan ayat, \"Dan mereka lebih mementingkan yang lain, meskipun mereka sendiri sangat kesusahan.\" (QS. Alhasyr 9)."},{"p":"Bukhari","n":4634,"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍذَكَرَ لِي ذِكْرًا مِنْ حَدِيثِهِ فَانْطَلَقْتُ حَتَّى دَخَلْتُ عَلَى مَالِكِ بْنِ أَوْسٍ فَسَأَلْتُهُ فَقَالَ مَالِكٌ انْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى عُمَرَ إِذْ أَتَاهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ يَسْتَأْذِنُونَ قَالَ نَعَمْ فَأَذِنَ لَهُمْ قَالَ فَدَخَلُوا وَسَلَّمُوا فَجَلَسُوا ثُمَّ لَبِثَ يَرْفَا قَلِيلًا فَقَالَ لِعُمَرَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ قَالَ نَعَمْ فَأَذِنَ لَهُمَا فَلَمَّا دَخَلَا سَلَّمَا وَجَلَسَا فَقَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا فَقَالَ الرَّهْطُ عُثْمَانُ وَأَصْحَابُهُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ فَقَالَ عُمَرُ اتَّئِدُوا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُ قَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَ قَالَا قَدْ قَالَ ذَلِكَ قَالَ عُمَرُ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ كَانَ قَدْ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَالِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ قَالَ اللَّهُ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ لَقَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ ثُمَّ تَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ فَقَبَضَهَا أَبُو بَكْرٍ يَعْمَلُ فِيهَا بِمَا عَمِلَ بِهِ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمَا حِينَئِذٍ وَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ تَزْعُمَانِ أَنَّ أَبَا بَكْرٍ كَذَا وَكَذَا وَاللَّهُ يَعْلَمُ أَنَّهُ فِيهَا صَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ فَقَبَضْتُهَا سَنَتَيْنِ أَعْمَلُ فِيهَا بِمَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ ثُمَّ جِئْتُمَانِي وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا جَمِيعٌ جِئْتَنِي تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكَ وَأَتَى هَذَا يَسْأَلُنِي نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ إِنْ شِئْتُمَا دَفَعْتُهُ إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهَا بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِمَا عَمِلَ بِهِ فِيهَا أَبُو بَكْرٍ وَبِمَا عَمِلْتُ بِهِ فِيهَا مُنْذُ وُلِّيتُهَا وَإِلَّا فَلَا تُكَلِّمَانِي فِيهَا فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا بِذَلِكَ فَدَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ أَنْشُدُكُمْ بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْهِمَا بِذَلِكَ فَقَالَ الرَّهْطُ نَعَمْ قَالَ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ قَالَا نَعَمْ قَالَ أَفَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَالَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهَا فَادْفَعَاهَا فَأَنَا أَكْفِيَكُمَاهَا","trj":"Telah menceritakan kepada kami [Sa'id bin Ufair] ia berkata; Telah menceritakan kepadaku [Al Laits] ia berkata; Telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Malik bin Aus bin Al Hadatsan] dan bahwasanya [Muhammad bin Jubair bin Muth'im] menyebutkan suatu hadits padaku. Maka aku pun pergi menemui Malik bin Aus dan bertanya padanya. Maka [Malik] berkata; Aku pergi hingga bertemu dengan [Umar]. Lalu pelayannya pun menemuinya dan berkata pada Umar, \"Apakah Anda mengizinkan [Utsman], [Abdurrahman], [Az Zubair] dan [Sa'dari] untuk masuk?\" Ia menjawab, \"Ya.\" Lalu sang pelayan mengizinkan mereka masuk dan mereka pun mengucapkan salam kemudian duduk. Sang pelayan kembali menutup dan berkata pada Umar, \"Apakah Anda juga mengizinkan pada [Ali] dan [Abbas]\" Umar menjawab, \"Ya.\" Pelayan itu pun mengizinkan keduanya masuk. Dan ketika kedua masuk, keduanya pun mengucapkan salam dan duduk. Kemudian Abbas berkata, \"Wahai Amirul Mukminin, putuskanlah perkara antara aku dan orang ini.\" lalu Utsman berserta kelompoknya berkata, \"Wahai Amirul Mukminin, berilah keputusan antara mereka berdua dan istirahatkanlah yang satu dari yang lainnya.\" Maka Umar berkata, \"Aku menyumpah kalian dengan nama Allah yang dengan-Nya berdirilah langit dan bumi, sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya kami tidaklah mewariskan. Dan apa yang kami tinggalkan adalah harta sedekah.' Yang dimaksud oleh Rasulullah shallallahu 'alaihi wasallam adalah dirinya sendiri. Ar Rahth (sekelompok orang itu) pun berkata, \"Sesungguhnya beliau telah mengatakan hal itu.\" Kemudian Umar menghadap ke arah Ali dan dan Abbas dan berkata, \"Aku menyumpahkah kalian dengan nama Allah, apakah kalian berdua tahu bahwa Rasulullah shallallahu 'alaihi wasallam telah mengatakan hal itu?\" keduanya menjawab, \"Ya, beliau telah mengatakan hal itu.\" Selanjutnya Umar berkata, \"Aku menceritakan kepada kalian mengenai perkara ini. Sesungguhnya Allah telah mengkhususkan untuk Rasulullah shallallahu 'alaihi wasallam di dalam harta ini dengan sesuatu yang belum pernah Dia berikan kepada orang lain selainnya. Allah berfirman: 'MAA AFAA`ALLAHU 'ALAA RASUULIHI MINHUM FAMAA AUJAFTUM 'ALAIHI MIN KHAIL.' (QS. Alhasyr. 6).Hingga firman-Nya: 'QADIIR.' Maka harta ini adalah murni untuk diri Rasulullah shallallahu 'alaihi wasallam. Dan demi Allah, Rasulullah Shallallahu'alaihiwasallam dahulu tidak pernah memberikannya kepada selain kalian (ahlu bait) dan tidak pula beliau lebih mementingkan dirinya sendiri daripadsa kalian. Sesungguhnya beliau telah memberikannya dan menyerahkannya pada kalian, hingga darinya tersisalah harta ini. Dulu, Rasulullah shallallahu 'alaihi wasallam memberi nafkah tahunan kepada keluarganya dari harta ini, kemudian sisanya beliau ambil dan menjadikannya sebagai harta Allah. Begitulah Rasulullah shallallahu 'alaihi wasallam mengisi menjalani kehidupannya. Aku menyumpah kalian dengan nama Allah, apakah kalian mengetahui hal itu?\" Mereka menjawab, \"Ya.\" Umar kemudian berkata kepada Ali dan Abbas, \"Aku menyumpah kalian dengan nama Allah, apakah kalian juga tahu akan hal itu?\" keduanya menjawab: \"Ya.\" Umar melanjutkan, \"Kemudian Nabi shallallahu 'alaihi wasallam wafat dan berkatalah Abu Bakar, 'Aku adalah wali Rasulullah.' Maka Abu Bakar pun menanganinya. Ia mengelolanya sebagaimana yang diperbuat oleh Rasulullah shallallahu 'alaihi wasallam. Dan ada pun kalian berdua -Umar menghadap ke arah Ali dan Abbas- menyangka bahwa Abu Bakar adalah begini dan begitu. Demi Allah, sesungguhnya dala hal itu Abu Bakar adalah telah bertindak benar, berbuat baik dan juga rasyid berada di atas kebenaran. Kemudian setelah Abu Bakar Wafat, aku pun berkata, 'Aku adalah wali Rasulullah shallallahu 'alaihi wasallam dan Abu bakar.' Sehingga aku pun menanganinya selama dua tahun. Aku mengelolanya sebagaimana yang telah diperbuat oleh Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar. Kemudian kalian berdua bersepakat mendatangiku. Kamu (Ibn Abbas) mendatangiku untuk meminta bagianmu dari anak saudaramu (maksudnya Rasulullah), dan yang ini (Ali) juga mendatangiku untuk meminta bagian isterinya dari jalur bapaknya (maksudnya Rasulullah). Maka aku katakan, 'Jika kalian mau, maka aku akan menyerahkannya pada kalian berdua dengan satu catatan, bahwa di atas kalian berdua terdapat janji Allah. Kalian berdua benar-benar sadar akan apa yang telah diperbuat oleh Rasulullah shallallahu 'alaihi wasallam di dalamnya, dan juga apa yang telah diperbuat oleh Abu Bakar serta apa yang aku perbuat sejak aku menanganinya. Kalau tidak, maka janganlah kalian berdua berkata lagi padaku tentang harta itu, 'Berikanlah harta itu pada kami.' Sehingga aku akan menyerahkan harta itu pada kalian berdua. Aku menyumpah kalian berdua dengan nama Allah, apakakah aku menyerahkannya pada keduanya?\" sekelompok orang itu pun menjawab, \"Ya.\" Kemudian Umar berpaling ke arah Ali dan Abbas seraya bertanya, \"Aku menyumpah kalian dengan nama Allah, apakah aku menyerahkannya pada kalian berdua?\" keduanya menjawab, \"Ya.\" Umar berkata lagi, \" Apakah kalian berdua memintaku keputusan selain yang telah kuutarakan tadi? Demi Dzat yang dengan seijin-Nya langit dan bumi tegak, saya tidak akan memutuskan peninggalan Rasulullah tersebut dengan keputusan lain hingga kiamat tiba, seandainya kamu berdua tidak mampu mengelolanya, tolong kalian berdua serahkan, dan saya yang akan menggantikan kalian berdua.\""},{"p":"Bukhari","n":5171,"ar":"حَدَّثَنَا عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ عَبْدُ اللَّهِلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ تَعَالَى مَالِي لَا أَلْعَنُ مَنْ لَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ }","trj":"Telah menceritakan kepada kami [Utsman] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Alqamah], [Abdullah] mengatakan; \"Allah melaknat orang yang mentato dan orang yang meminta ditato, orang yang mencukur habis alis dan merenggangkan gigi untuk kecantikan dengan merubah ciptaan Allah Ta'ala, kenapa saya tidak melaknat orang yang dilaknat Nabi shallallahu 'alaihi wasallam sementara dalam kitabullah telah termaktub Dan sesuatu yang datang dari rasul, maka ambillah (QS Al Hasyr; 7).\""},{"p":"Bukhari","n":5178,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَلَعَنَ عَبْدُ اللَّهِ الْوَاشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَقَالَتْ أُمُّ يَعْقُوبَ مَا هَذَا قَالَ عَبْدُ اللَّهِ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ وَفِي كِتَابِ اللَّهِ قَالَتْ وَاللَّهِ لَقَدْ قَرَأْتُ مَا بَيْنَ اللَّوْحَيْنِ فَمَا وَجَدْتُهُ قَالَ وَاللَّهِ لَئِنْ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dia berkata; [Abdullah] melaknat orang yang mentato, mencukur habis alis mata, merenggangkan gigi (denga kawat dll) untuk kecantikan dengan merubah ciptaan Allah, Ummu Ya'qub berkata; \"Apa maksudnya ini?\" Abdullah mengatakan; \"Bagaimana aku tidak melaknat orang yang dilaknat Rasulullah dan telah tercatat pula dalam kitabullah. Ummu Ya'qub berkata; \"Saya telah membaca dalam mushaf, namun saya tidak mendapatkan hal itu.\" Abdullah berkata; \"Demi Allah, sekiranya kamu membacanya, niscaya kamu akan mendapatkannya yaitu Dan sesuatu yang datang dari Rasul maka ambillah dan yang di larang olehnya maka jauhilah QS Al Hasyr: 7."},{"p":"Bukhari","n":5898,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ ذَكَرَ لِيمِنْ حَدِيثِهِ ذَلِكَ فَانْطَلَقْتُ حَتَّى دَخَلْتُ عَلَيْهِ فَسَأَلْتُهُ فَقَالَ انْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى عُمَرَ فَأَتَاهُ حَاجِبُهُ يَرْفَأُ فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ قَالَ نَعَمْ فَأَذِنَ لَهُمْ ثُمَّ قَالَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ قَالَ نَعَمْ قَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا قَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُ فَقَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَ قَالَا قَدْ قَالَ ذَلِكَ قَالَ عُمَرُ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ قَدْ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْفَيْءِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ فَقَالَ عَزَّ وَجَلَّ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ لَقَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ مِنْ هَذَا الْمَالِ نَفَقَةَ سَنَتِهِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ بِذَاكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ فَتَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهَا فَعَمِلَ بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ وَلِيِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضْتُهَا سَنَتَيْنِ أَعْمَلُ فِيهَا مَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ ثُمَّ جِئْتُمَانِي وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا جَمِيعٌ جِئْتَنِي تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكَ وَأَتَانِي هَذَا يَسْأَلُنِي نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ إِنْ شِئْتُمَا دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ فَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا فَادْفَعَاهَا إِلَيَّ فَأَنَا أَكْفِيكُمَاهَا","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] mengatakan, telah mengabarkan kepadaku [Malik bin Aus bin Al Hadatsan] dan [Muhammad bin Jubair bin Muth'im] menyebutkan kepadaku diantara haditsnya; 'maka aku berangkat hingga menemuinya dan bertanya kepadanya, dia menjawab; 'Aku berangkat hingga aku menemui [Umar]. Umar lantas ditemui oleh pengawal rumahnya dan mengucapkan selamat datang, kemudian ia bertanya; 'Apakah anda berkenan memberi izin untuk [Utsman], [Abdurrahman], [Zubai] r, dan [Sa'dari] ' 'Tentu' jawabnya. Penjaga itu pun mengizinkan mereka. kemudian dia bertanya lagi; 'apakah anda memberi izin kepada [Ali] dan [Abbas] ' 'ya' Jawab Umar. Abbas kemudian berkata; 'Wahai amirul mukminin, putuskanlah antara aku dan orang ini! ' Umar menjawab; 'Saya bersumpah kepada kalian dengan nama Allah yang karena- izin-Nya langit dan bumi tegak, bukankah kalian telah tahu bahwa Rasulullah Shallallahu'alaihi wa sallam telah bersabda: \"Kami tidak diwarisian, dan apa yang kami tinggalkan adalah sedekah!\" yang Rasulullah maksudkan adalah beliau sendiri.' Sekumpulan sahabat berkata; 'Nabi pernah mengatakan yang demikian.' Umar kemudian menemui Ali dan Abbas dan bertanya; 'bukankah kalian berdua tahu bahwa Rasulullah Shallallahu'alaihiwasallam telah menyabdakan yang demikian? ' Keduanya menjawab; 'Betul, Beliau telah bersabda sedemikian itu.' Umar berkata; 'sekarang saya akan menceritakan kepada kalian tentang persoalan ini, sesungguhnya Allah telah memberi pemberian special kepada Rasul-Nya Shallallahu'alaihiwasallam tentang harta fai` ini, dengan sesuatu yang tidak diberikan-Nya kepada seorang pun selainnya. Allah berfirman: 'Apa saja yang Allah berikan kepada Rasul-Nya…hingga firman-Nya Sesungguhnya Allah Maha Berkuasa. (QS. Alhasyr 1). Karenanya harta fai` tersebut adalah murni untuk Rasulullah Shallallahu'alaihiwasallam, demi Allah beliau tidak memberikannya secara special untuk kalian dan tidak pula mengutamakannya untuk kalian, sesungguhnya beliau juga telah memberikan harta itu kepada kalian dan meratakannya kepada kalian hingga tersisa dari harta ini, selanjutnya Nabi pergunakan harta itu untuk menafkahi keluarganya selama setahun, beliau mengambil harta sisanya dan beliau salurkan untuk harta Allah. Begitulah Rasulullah Shallallahu'alaihiwasallam memperlakukan harta itu semasa hidupnya. Saya bersumpah kepada kalian atas nama Allah, Bukankah kalian tahu terhadap itu semua? ' Mereka menjawab; 'Iya'. Kemudian Umar mengatakan secara khusus kepada Ali dan Abbas; 'Saya bersumpah kepada kalian berdua atas nama Allah, bukankah kalian berdua tahu itu semua? ' Keduanya menjawab; 'Benar'. Umar melanjutkan; 'Kemudian Allah mewafatkan Nabi-NYA Shallallahu'alaihiwasallam, lantas Abu Bakar berkata; 'Aku adalah wali Rasulullah Shallallahu'alaihiwasallam, ' dan dia memegang harta itu kemudian mengelola sebagaimana Rasulullah Shallallahu'alaihiwasallam mengelola, kemudian Allah mewafatkan Abu Bakar, sehingga aku katakan; 'Aku adalah wali dari walinya Rasulullah Shallallahu'alaihiwasallam, sehingga aku pegang harta itu selama dua tahun dan aku kelola sebagaimana Rasulullah Shallallahu'alaihiwasallam dan Abu Bakar mengelolanya, kemudian kalian berdua mendatangiku sedang ucapan kalian satu, dan perkara kalian berdua sepakat persis, kalian mendatangiku dengan harapan memintaku bagianmu lewat lajur keponakanmu, sedang orang ini memintaku bagian isterinya lewat lajur ayahnya, maka kutegaskan; Jika kalian berkenan, tanah itu akan kuserahkan kepada kalian berdua, sehingga kalian berdua memperoleh keputusan selain itu dariku, demi Allah yang atas seizin-Nya bumi dan langit menjadi tegak, Saya tak akan menetapkan keputusan selain itu hingga kiamat tiba, kalaulah kalian berdua merasa tidak mampu, serahkan padaku, saya akan mengelola harta itu sebagai ganti kalian.'"},{"p":"Bukhari","n":6421,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسٍ النَّصْرِيُّ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ ذَكَرَ لِيذِكْرًا مِنْ ذَلِكَ فَدَخَلْتُ عَلَى مَالِكٍ فَسَأَلْتُهُ فَقَالَ انْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى عُمَرَ أَتَاهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ يَسْتَأْذِنُونَ قَالَ نَعَمْ فَدَخَلُوا فَسَلَّمُوا وَجَلَسُوا فَقَالَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ فَأَذِنَ لَهُمَا قَالَ الْعَبَّاسُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ الظَّالِمِ اسْتَبَّا فَقَالَ الرَّهْطُ عُثْمَانُ وَأَصْحَابُهُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ فَقَالَ اتَّئِدُوا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُقَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَ قَالَا نَعَمْ قَالَ عُمَرُ فَإِنِّي مُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَالِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ فَإِنَّ اللَّهَ يَقُولُ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ }الْآيَةَ فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ وَقَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ فَقَالُوا نَعَمْ ثُمَّ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا اللَّهَ هَلْ تَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ ثُمَّ تَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهَا أَبُو بَكْرٍ فَعَمِلَ فِيهَا بِمَا عَمِلَ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمَا حِينَئِذٍ وَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ تَزْعُمَانِ أَنَّ أَبَا بَكْرٍ فِيهَا كَذَا وَاللَّهُ يَعْلَمُ أَنَّهُ فِيهَا صَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ فَقَبَضْتُهَا سَنَتَيْنِ أَعْمَلُ فِيهَا بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ ثُمَّ جِئْتُمَانِي وَكَلِمَتُكُمَا عَلَى كَلِمَةٍ وَاحِدَةٍ وَأَمْرُكُمَا جَمِيعٌ جِئْتَنِي تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكِ وَأَتَانِي هَذَا يَسْأَلُنِي نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ إِنْ شِئْتُمَا دَفَعْتُهَا إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهَا بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِمَا عَمِلَ فِيهَا أَبُو بَكْرٍ وَبِمَا عَمِلْتُ فِيهَا مُنْذُ وَلِيتُهَا وَإِلَّا فَلَا تُكَلِّمَانِي فِيهَا فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا بِذَلِكَ فَدَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ أَنْشُدُكُمْ بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْهِمَا بِذَلِكَ قَالَ الرَّهْطُ نَعَمْ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ قَالَا نَعَمْ قَالَ أَفَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَالَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهَا فَادْفَعَاهَا إِلَيَّ فَأَنَا أَكْفِيكُمَاهَا","trj":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibn Syihab] berkata, telah mengabarkan kepadaku [Malik bin Aus an Nashri], dan [Muhammad bin Jubair bin Muth'im] pernah mengingatkan aku tentang hal itu. AKu menemui Malik dan aku bertanya kepadanya.\" Ia meneruskan, \"Aku terus bertolak hingga kutemui [Umar], kemudian penjaga rumahnya bertanya, \"Apakah engkau berkenan memberi ijin [Utsman], [Abdurrahman bin Auf], [Zubair], dan [Sa'd] untuk bertemu?\" Umar menjawab, \"Ya.\" Mereka pun masuk, mengucapkan salam dan duduk. Si penjaga pintu bertanya lagi, \"Apakah anda memberi ijin untuk [Ali] dan [Abbas]\" Umar pun mengijinkan keduanya. Abbas kemudian bertanya, \"Wahai Amirul Mukminin, putuskanlah antara aku dan orang yang zhalim yang mencela.\" Sekelompok orang yang di antaranya Utsman dan para sahabatnya kemudian berkata, \"Wahai Amirul Mukminin, putuskanlah antara keduanya dan nyamankanlah salah satunya dari yang lain.\" Umar menjawab, \"Tolong kalian yang bijak, aku bersumpah atas kalian dengan nama Allah yang karena ijin-Nya langit dan bumi tegak. Tahukah kalian bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kami tidak diwarisi, apa yang kami tinggalkan adalah sedekah (bukan warisan) '? Maka kumpulan sahabat tadi menjawab, \"Memang beliau pernah bersabda yang demikian ini.\" Umar lalu menemui Ali dan Abbas seraya berkata, \"Aku bersumpah atas kalian dengan nama Allah, bukankah kalian berdua tahu bahwa Rasulullah pernah bersabda yang sedemikian tadi?\" Keduanya menjawab, \"Ya.\" Umar lalu berkata, \"Karenanya aku sekarang bicara kepada kalian tentang masalah (harta nabi). Sesungguhnya Allah mengkhususkan hanya untuk rasul-Nya shallallahu 'alaihi wasallam dalam hal harta ini, suatu yang tak akan diberikan-Nya kepada seorang pun, sebab Allah berfirman: '(Apa yang Allah berikan kepada rasul-Nya dari para tawanan, yang kamu dapatkan dengan tanpa mengerahkan… dan seterusnya (Qs. Al Hasyr; 6), kesemuanya ini adalah khusus bagi Rasulullah shallallahu 'alaihi wasallam. Kemudian demi Allah, beliau tidak memberikannya dan tidak pula menganugerahkanya secara khusus untuk kalian. Dahulu Rasul telah memberikannya kepada kalian dan membagikannya di tengah-tengah kalian, hingga harta ini masih tersisa. Dan Nabi shallallahu 'alaihi wasallam memberi belanja tahunan kepada keluarganya dari harta ini, kemudian beliau tarik sisanya dan beliau jadikan sebagai harta Allah, dan begitulah beliau mengelola hartanya semasa hidupnya. Aku bersumpah atas kalian dengan nama Allah, bukankah kalian tahu terhadap itu semua? Mereka menjawab, \"Ya.\" Kemudian Umar berkata kepada Ali dan Abbas, \"Aku bersumpah atas kalian dengan nama Allah, bukankah kalian berdua tahu tentang ini semua?\" keduanya menjawab, \"Ya.\" Umar meneruskan bicaranya, \"Kemudian Allah mewafatkan nabi-Nya shallallahu 'alaihi wasallam, lantas Abu Bakar mengatakan aku adalah wali Rasulullah shallallahu 'alaihi wasallam sehingga Abu Bakar mewenanginya dan mengelolanya sebagaimana Rasulullah shallallahu 'alaihi wasallam mengelolanya, dan kamu ketika itu juga ada.\" Lantas Umar menghadap Ali dan Abbas dengan mengatakan, \"Kalian beranggapan bahwa Abu Bakar seperti ini dan seperti ini, padahal Allah tahu bahwa dia terhadap harta itu betul-betul jujur, baik, lurus, dan mengikuti kebenaran. Kemudian Allah mewafatkan Abu bakar, maka aku (Umar) katakan bahwa aku sekarang adalah wali Rasulullah shallallahu 'alaihi wasallam dan juga wali Abu bakar, maka aku mewenangi harta itu dua tahun yang aku kelola sebagaimana Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar mengelola, lantas anehnya kalian berdua mendatangi aku sedang kalian kompak, sama-sama sepakat, kamu menemuiku untuk meminta bagianmu dari anak saudaramu (ucapan ini Umar tujukan kepada Abbas, sebab ia adalah paman Rasulullah), sedang si ini (maksudnya Ali) datang kepadaku memintaku bagian isterinya dari ayahnya (Ucapan ini Umar tujukan kepada Ali, sebab ia adalah menantu Rasulullah). Maka aku katakan, 'Jikalah kalian berkenan, harta itu aku serahkan kepada kalian berdua, hanya kalian harus menerima resiko tanggung jawab dari janji Allah dan ikrar-Nya, yaitu agar kalian berdua mengelolanya sebagaimana Rasulullah shallallahu 'alaihi wasallam mengelola, dan juga sebagaimana Abu Bakar mengelola, dan juga sebagaimana aku mengolala semenjak aku mewenanginya. Kalaulah kamu berdua tidak bisa, tolong jangan kalian berdua mengajakku bicara tentang harta itu, jangan kalian berdua berkata, 'Serahkan harta itu kepada kami berdua' lantas aku katakan, 'kuserahkan kepadamu berdua'. Adapun sekarang, aku bersumpah kepada kalian dengan nama Allah, bukankah telah aku serahkan sekarang kepada keduanya?\" Beberapa kumpulan sahabat yang hadir menjawab, \"Benar, \" lantas Umar menghadap Ali dan Abbas seraya berkata, \"Aku bersumpah atas kalian berdua (dengan nama Allah), bukankah telah aku serahkan kepada kalian berdua masalah harta itu?\" Keduanya menjawab, \"Benar.\" Umar kemudian berkata, \"Apakah kalian berdua mencari-cari keputusan selain itu setelah memperolehnya dariku? Demi Dzat yang karena seijin-Nya bumi dan langit menjadi tegak, selama-lamanya aku tidak akan memutuskan keputusan selain itu hingga kiamat tiba. Maka jika kalian berdua tidak mampu, serahkan saja kepadaku, sebab aku bisa mengganti kalian berdua.\""},{"p":"Darimi","n":2881,"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ مَنْ قَرَأَ ثَلَاثَ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ إِذَا أَصْبَحَ فَمَاتَ مِنْ يَوْمِهِ ذَلِكَ طُبِعَ بِطَابَعِ الشُّهَدَاءِ وَإِنْ قَرَأَ إِذَا أَمْسَى فَمَاتَ مِنْ لَيْلَتِهِ طُبِعَ بِطَابَعِ الشُّهَدَاءِ","trj":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Hisyam] dari [Al Hasan] ia berkata; Barangsiapa yang membaca tiga ayat dari akhir surat Al Hasyr ketika berada di waktu pagi, lalu ia meninggal di hari itu maka ia dicap sebagai syahid. jika ia membacanya ketika berada di waktu sore, lalu ia meninggal pada malam itu maka ia dicap sebagai syahid."},{"p":"Darimi","n":2883,"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْفَرَجِ الْبَغْدَادِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ حَدَّثَنَا خَالِدُ بْنُ طَهْمَانَ أَبُو الْعَلَاءِ الْخَفَّافُ حَدَّثَنِي نَافِعُ بْنُ أَبِي نَافِعٍ عَنْ مَعْقِلِ بْنِ يَسَارٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ حِينَ يُصْبِحُ أَعُوذُ بِاللَّهِ السَّمِيعِ الْعَلِيمِ مِنْ الشَّيْطَانِ الرَّجِيمِ وَثَلَاثَ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَكَّلَ اللَّهُ بِهِ سَبْعِينَ أَلْفَ مَلَكٍ يُصَلُّونَ عَلَيْهِ حَتَّى يُمْسِيَ وَإِنْ قَالَهَا مَسَاءً فَمِثْلُ ذَلِكَ حَتَّى يُصْبِحَ","trj":"Telah menceritakan kepada kami [Muhammad bin Al Faraj Al Baghdadi] telah menceritakan kepada kami [Muhammad bin Abdullah bin Az Zubair] telah menceritakan kepada kami [Khalid bin Thahman Abu Al 'Ala` Al Khaffaf] telah menceritakan kepadaku [Nafi' bin Abu Nafi'] dari [Ma'qil bin Yasar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang mengucapkan ketika berada di waktu pagi; A'UDZUBILLAHIS SAMI'IL 'ALIM MINASY SYAITHANIR RAJIM dan tiga ayat dari akhir surat Al Hasyr, maka Allah akan menugaskan tujuh puluh ribu malaikat untuk memintakan ampun untuknya hingga ia berada di waktu sore. Dan jika ia membacanya di waktu sore, maka Allah akan menugaskan tujuh puluh ribu malaikat untuk memintakan ampun untuknya juga hingga ia berada di waktu pagi.\""},{"p":"Ibnu Majah","n":2799,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً }الْآيَةَ الْآيَةَ","trj":"Telah menceritakan kepada kami [Muhammad bin Rumh]; telah menberitakan kepada kami [Al Laits bin Sa'ad] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam membakar pohon kurma bani Nadlir dan menebasnya, yaitu kawasan Buwairah, kemudian Allah Subhanahu Wa Ta'ala menurunkan ayat: 'Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya (Qs. Al Hasyr 99: 5).'\""},{"p":"Ibnu Majah","n":3504,"ar":"حَدَّثَنَا هَارُونُ بْنُ حَيَّانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَنْبَأَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو جَنَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ أَبِي لَيْلَى قَالَكُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ أَعْرَابِيٌّ فَقَالَ إِنَّ لِي أَخًا وَجِعًا قَالَ مَا وَجَعُ أَخِيكَ قَالَ بِهِ لَمَمٌ قَالَ اذْهَبْ فَأْتِنِي بِهِ قَالَ فَذَهَبَ فَجَاءَ بِهِ فَأَجْلَسَهُ بَيْنَ يَدَيْهِ فَسَمِعْتُهُ عَوَّذَهُ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ الْبَقَرَةِ وَآيَتَيْنِ مِنْ وَسَطِهَا{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ خَاتِمَتِهَا وَآيَةٍ مِنْ آلِ عِمْرَانَ أَحْسِبُهُ قَالَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ }الْآيَةَ وَآيَةٍ مِنْ الْمُؤْمِنِينَ{ وَمَنْ يَدْعُ مَعَ اللَّهِ إِلَهًا آخَرَ لَا بُرْهَانَ لَهُ بِهِ }وَآيَةٍ مِنْ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا مَا اتَّخَذَ صَاحِبَةً وَلَا وَلَدًا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الْأَعْرَابِيُّ قَدْ بَرَأَ لَيْسَ بِهِ بَأْسٌ","trj":"Telah menceritakan kepada kami [Harun bin Hayyan] telah menceritakan kepada kami [Ibrahim bin Musa] telah memberitakan kepada kami ['Abdah bin Sulaiman] telah menceritakan kepada kami [Abu Janab] dari [Abdurrahman bin Abu Laila] dari ayahnya [Abu Laila] dia berkata, \"Ketika aku sedang duduk di samping Nabi shallallahu 'alaihi wasallam, tiba-tiba datang seorang Arab Badui seraya berkata, 'Sesungguhnya aku mempunyai saudara yang menderita sakit.\" Beliau bertanya: \"Apa sakit yang meninmpa saudaramu?\" Dia menjawab, \"Dia terserang ayan.\" Beliau bersabda: \"Pergi dan bawalah dia kesini.\" Maka dia pergi dan kembali (kepada beliau) bersama saudaranya dan mendudukkannya di depan beliau, maka aku mendengar beliau memberikan perlindungan kepadanya dengan Al Fatihah, empat ayat dari permulaan surat Al Baqarah, dua ayat dari tengahnya dan (ayat) WA ILAAHUKUM ILAAHUWWAAHID (dan tuhan kalian adalah tuhan yang satu), ayat kursi, tiga ayat dari penghujung surat Al Baqarah, dan satu ayat dari surat Ali 'Imran. Aku yakin beliau mengucapkan: \"SYAHIDALLAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah bersaksi bahwa tidak ada ilah yang berhak disembah kecuali Dia) '. Beliau juga membaca satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAHULLADZI KHALAQ (sesungguhnya Rabb kalian adalah yang menciptakan) ', satu ayat dari surat Al MuKminun: WA MAN YADA'U MA'ALLAHI ILAAHNA AAKHAR LAA BURHAANA LAHU BIHI '(Dan barang siapa yang menyeru bersama dengan Allah yaitu ilah yang lain, maka tidak ada petunjuk baginya), satu ayat dari surat Al Jin: WA ANNAHU TA'ALA JADDU RABBINAA MATTAKHADZA SHAAHIBATAN WA LAA WALADA (Dan bahwasannya Maha Tinggi kebesaran Rabb kami, Dia tidak beristeri dan tidak (pula) beranak) '. Sepuluh ayat dari surat Ash Shaffaat, tiga ayat dari akhir surat Al Hasyr, dan QULHUWALLAHU AHAD, dan dua mu'awidzatain. Kemudian orang Arab Badui itu bangun dan sembuh seakan-akan tidak menderita sakit.\""},{"p":"Muslim","n":1605,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ الْمُنْذِرِ بْنِ جَرِيرٍ عَنْ أَبِيهِ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَدْرِ النَّهَارِ قَالَ فَجَاءَهُ قَوْمٌ حُفَاةٌ عُرَاةٌ مُجْتَابِي النِّمَارِ أَوْ الْعَبَاءِ مُتَقَلِّدِي السُّيُوفِ عَامَّتُهُمْ مِنْ مُضَرَ بَلْ كُلُّهُمْ مِنْ مُضَرَ فَتَمَعَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَا رَأَى بِهِمْ مِنْ الْفَاقَةِ فَدَخَلَ ثُمَّ خَرَجَ فَأَمَرَ بِلَالًا فَأَذَّنَ وَأَقَامَ فَصَلَّى ثُمَّ خَطَبَ فَقَالَ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ إِلَى آخِرِ الْآيَةِ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }وَالْآيَةَ الَّتِي فِي الْحَشْرِ{ اتَّقُوا اللَّهَ وَلْتَنْظُرْ نَفْسٌ مَا قَدَّمَتْ لِغَدٍ وَاتَّقُوا اللَّهَ }تَصَدَّقَ رَجُلٌ مِنْ دِينَارِهِ مِنْ دِرْهَمِهِ مِنْ ثَوْبِهِ مِنْ صَاعِ بُرِّهِ مِنْ صَاعِ تَمْرِهِ حَتَّى قَالَ وَلَوْ بِشِقِّ تَمْرَةٍ قَالَ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ بِصُرَّةٍ كَادَتْ كَفُّهُ تَعْجِزُ عَنْهَا بَلْ قَدْ عَجَزَتْ قَالَ ثُمَّ تَتَابَعَ النَّاسُ حَتَّى رَأَيْتُ كَوْمَيْنِ مِنْ طَعَامٍ وَثِيَابٍ حَتَّى رَأَيْتُ وَجْهَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَهَلَّلُ كَأَنَّهُ مُذْهَبَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَنَّ فِي الْإِسْلَامِ سُنَّةً حَسَنَةً فَلَهُ أَجْرُهَا وَأَجْرُ مَنْ عَمِلَ بِهَا بَعْدَهُ مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أُجُورِهِمْ شَيْءٌ وَمَنْ سَنَّ فِي الْإِسْلَامِ سُنَّةً سَيِّئَةً كَانَ عَلَيْهِ وِزْرُهَا وَوِزْرُ مَنْ عَمِلَ بِهَا مِنْ بَعْدِهِ مِنْ غَيْرِ أَنْ يَنْقُصَ مِنْ أَوْزَارِهِمْ شَيْءٌو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي قَالَا جَمِيعًا حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَوْنُ بْنُ أَبِي جُحَيْفَةَ قَالَ سَمِعْتُ الْمُنْذِرَ بْنَ جَرِيرٍ عَنْ أَبِيهِ قَالَ كُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدْرَ النَّهَارِ بِمِثْلِ حَدِيثِ ابْنِ جَعْفَرٍ وَفِي حَدِيثِ ابْنِ مُعَاذٍ مِنْ الزِّيَادَةِ قَالَ ثُمَّ صَلَّى الظُّهْرَ ثُمَّ خَطَبَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ وَأَبُو كَامِلٍ وَمُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ الْأُمَوِيُّ قَالُوا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ الْمُنْذِرِ بْنِ جَرِيرٍ عَنْ أَبِيهِ قَالَ كُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهُ قَوْمٌ مُجْتَابِي النِّمَارِ وَسَاقُوا الْحَدِيثَ بِقِصَّتِهِ وَفِيهِ فَصَلَّى الظُّهْرَ ثُمَّ صَعِدَ مِنْبَرًا صَغِيرًا فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ اللَّهَ أَنْزَلَ فِي كِتَابِهِ{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمُ }الْآيَةَ و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ بْنِ يَزِيدَ وَأَبِي الضُّحَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ هِلَالٍ الْعَبْسِيِّ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَ جَاءَ نَاسٌ مِنْ الْأَعْرَابِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ الصُّوفُ فَرَأَى سُوءَ حَالِهِمْ قَدْ أَصَابَتْهُمْ حَاجَةٌ فَذَكَرَ بِمَعْنَى حَدِيثِهِمْ","trj":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna Al Anazi] telah mengabarkan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Aun bin Abu Juhaifah] dari [Al Mundzir bin Jarir] dari [Jarir] ia berkata; Pada suatu pagi, ketika kami berada dekat Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datang segerombongan orang tanpa sepatu, dan berpaiakan selembar kain yang diselimutkan ke badan mereka sambil menyandang pedang. Kebanyakan mereka, mungkin seluruhnya berasal dari suku Mudlar. Ketika melihat mereka, wajah Rasulullah shallallahu 'alaihi wasallam terharu lantaran kemiskinan mereka. Beliau masuk ke rumahnya dan keluar lagi. Maka disuruhnya Bilal adzan dan iqamah, sesudah itu beliau shalat. Sesudah shalat, beliau berpidato. Beliau membacakan firman Allah: \"Hai sekalian manusia, bertakwalah kepada Tuhan-mu yang Telah menciptakan kamu dari seorang diri…, \" hingga akhir ayat, \"Sesungguhnya Allah selalu mengawasi kalian.\" kemudian ayat yang terdapat dalam surat Al Hasyr: \"Hai orang-orang yang beriman, bertakwalah kepada Allah dan hendaklah setiap diri memperhatikan apa yang Telah diperbuatnya untuk hari esok (akhirat); dan bertakwalah kepada Allah..., \" Mendengar khutbah Nabi shallallahu 'alaihi wasallam itu, serta merta seorang laki-laki menyedekahkan dinar dan dirhamnya, pakaiannya, satu sha' gandum, satu sha' kurma sehingga Nabi shallallahu 'alaihi wasallam bersabda: \"Meskipun hanya dengan setengah biji kurma.\" Maka datang pula seorang laki-laki Anshar membawa sekantong yang hampir tak tergenggam oleh tangannya, bahkan tidak terangkat. Demikianlah, akhirnya orang-orang lain pun mengikuti pula memberikan sedekah mereka, sehingga kelihatan olehku sudah terkumpul dua tumpuk makanan dan pakaian, sehingga kelihatan olehku wajah Rasulullah shallallahu 'alaihi wasallam berubah menjadi bersinar bagaikan emas. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Barangsiapa yang memulai mengerjakan perbuatan baik dalam Islam, maka dia akan memperoleh pahalanya dan pahala orang yang mencontoh perbuatan itu, tanpa mengurangi pahala mereka sedikitpun. Dan barangsiapa yang memulai kebiasaan buruk, maka dia akan mendapatkan dosanya, dan dosa orang yang mengikutinya dengan tanpa mengurangi dosa mereka sedikit pun.\" Dan Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] Telah menceritakan kepada kami [Abu Usamah] -dalam jalur lain- Dan Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Anbari] Telah menceritakan kepada kami [bapakku] ia berkata, Telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Aun bin Abu Juhaifah] ia berkata, saya mendengar [Al Mundziri bin Jarir] dari [bapaknya] ia berkata; Suatu hari, kami berada di dekat Rasulullah shallallahu 'alaihi wasallam. Yakni sebagaimana hadits Ibnu Ja'far. Dan di dalam hadits Ibnu Mu'adz terdapat tambahan, yakni; Kemudian beliau shalat Zhuhur dan kemudian berkhutbah.\" Telah menceritakan kepadaku [Ubaidullah bin Umar Al Qawariri] dan [Abu Kami] dan [Muhammad bin Abdul Malik Al Umawi] mereka berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik bin Umair] dari [Al Mundziri bin Jarir] dari [bapaknya] ia berkata; Kami duduk di sisi Nabi shallallahu 'alaihi wasallam, lalu datanglah suatu rombongan yang tak beralas kaki. Ia pun menyebutkan hadits, dan didalamnya; Kemudian beliau shalat Zhuhur lalu naik mimbar kecil, memuji Allah dan menyanjung-Nya dan kemudian bersabda: \"Amma Ba'du, sesungguhnya Allah 'azza wajalla telah menurunkan di dalam kitab-Nya; 'Wahai sekalian manusia, bertakwalah kalian kepada Rabb kalian..\" Dan telah menceritakan kepadaku [Zuhair bin Harb] Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Musa bin Abdullah bin Yazid] dan [Abu Dluha] dari [Abdurrahman bin Hilal Al Absi] dari [Jarir bin Abdullah] ia berkata; Sekelompok orang Arab pegunungan mendatangi Rasulullah shallallahu 'alaihi wasallam dengan mengenakan sehelai kain Shuf (wool), dan beliau melihat keadaan mereka yang memprihatinkan, bahwa mereka benar-benar membutuhkan bantuan. Ia pun menyebutkan hadits yang semakna dengan hadits mereka."},{"p":"Muslim","n":3051,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَمُحَمَّدُ بْنُ رُمْحٍ قَالَا أَخْبَرَنَا اللَّيْثُ و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ زَادَ قُتَيْبَةُ وَابْنُ رُمْحٍ فِي حَدِيثِهِمَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Muhammad bin Rumh] keduanya berkata; telah mengabarkan kepada kami [Al Laits] dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah membakar dan menebang kebun kurma milik (Yahudi) Bani Nadlir di Buwairah, lalu Allah Azza Wa Jalla menurunkan ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya, maka (semua itu) adalah dengan izin Allah; dan Karena dia hendak memberikan kehinaan kepada orang-orang fasik) ' (Qs. Al Hasyr: 5)."},{"p":"Muslim","n":3052,"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ نَخْلَ بَنِي النَّضِيرِ وَحَرَّقَ وَلَهَا يَقُولُ حَسَّانُ وَهَانَ عَلَى سَرَاةِ بَنِي لُؤَيٍّحَرِيقٌ بِالْبُوَيْرَةِ مُسْتَطِيرُوَفِي ذَلِكَ نَزَلَتْ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا }الْآيَةَ","trj":"Telah menceritakan kepada kami [Sa'id bin Manshur] dan [Hannad bin As Sarry] keduanya berkata; telah menceritakan kepada kami [Ibnu Mubarak] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam pernah menebang dan membakar kebun kurma milik (Yahudi) Bani Nadlir, dalam peristiwa itu, Hassan sempat membaca sebait sya'ir: \"Alangkah terhinanya tokoh-tokoh Bani Lu`aiy saat kebakaran melumat kebun kurma mereka yang berada di daerah Buwairah.\" Sehubungan dengan itu, maka turunlah ayat: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya...) ' (Qs. Al Hasyr: 5)."},{"p":"Muslim","n":3069,"ar":"و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ الضُّبَعِيُّ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَنَّ مَالِكَ بْنَ أَوْسٍ حَدَّثَهُ قَالَ أَرْسَلَ إِلَيَّ عُمَرُ بْنُ الْخَطَّابِ فَجِئْتُهُ حِينَ تَعَالَى النَّهَارُ قَالَ فَوَجَدْتُهُ فِي بَيْتِهِ جَالِسًا عَلَى سَرِيرٍ مُفْضِيًا إِلَى رُمَالِهِ مُتَّكِئًا عَلَى وِسَادَةٍ مِنْ أَدَمٍ فَقَالَ لِي يَا مَالُ إِنَّهُ قَدْ دَفَّ أَهْلُ أَبْيَاتٍ مِنْ قَوْمِكَ وَقَدْ أَمَرْتُ فِيهِمْ بِرَضْخٍ فَخُذْهُ فَاقْسِمْهُ بَيْنَهُمْ قَالَ قُلْتُ لَوْ أَمَرْتَ بِهَذَا غَيْرِي قَالَ خُذْهُ يَا مَالُ قَالَ فَجَاءَ يَرْفَا فَقَالَ هَلْ لَكَ يَا أَمِيرَ الْمُؤْمِنِينَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَالزُّبَيْرِ وَسَعْدٍ فَقَالَ عُمَرُ نَعَمْ فَأَذِنَ لَهُمْ فَدَخَلُوا ثُمَّ جَاءَ فَقَالَ هَلْ لَكَ فِي عَبَّاسٍ وَعَلِيٍّ قَالَ نَعَمْ فَأَذِنَ لَهُمَا فَقَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا الْكَاذِبِ الْآثِمِ الْغَادِرِ الْخَائِنِ فَقَالَ الْقَوْمُ أَجَلْ يَا أَمِيرَ الْمُؤْمِنِينَ فَاقْضِ بَيْنَهُمْ وَأَرِحْهُمْ فَقَالَ مَالِكُ بْنُ أَوْسٍ يُخَيَّلُ إِلَيَّ أَنَّهُمْ قَدْ كَانُوا قَدَّمُوهُمْ لِذَلِكَفَقَالَ عُمَرُ اتَّئِدَا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالُوا نَعَمْ ثُمَّ أَقْبَلَ عَلَى الْعَبَّاسِ وَعَلِيٍّ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَاهُ صَدَقَةٌ قَالَا نَعَمْ فَقَالَ عُمَرُ إِنَّ اللَّهَ جَلَّ وَعَزَّ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَاصَّةٍ لَمْ يُخَصِّصْ بِهَا أَحَدًا غَيْرَهُ قَالَ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْ أَهْلِ الْقُرَى فَلِلَّهِ وَلِلرَّسُولِ }مَا أَدْرِي هَلْ قَرَأَ الْآيَةَ الَّتِي قَبْلَهَا أَمْ لَا قَالَ فَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَكُمْ أَمْوَالَ بَنِي النَّضِيرِ فَوَاللَّهِ مَا اسْتَأْثَرَ عَلَيْكُمْ وَلَا أَخَذَهَا دُونَكُمْ حَتَّى بَقِيَ هَذَا الْمَالُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُ مِنْهُ نَفَقَةَ سَنَةٍ ثُمَّ يَجْعَلُ مَا بَقِيَ أُسْوَةَ الْمَالِ ثُمَّ قَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَتَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ نَشَدَ عَبَّاسًا وَعَلِيًّا بِمِثْلِ مَا نَشَدَ بِهِ الْقَوْمَ أَتَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ قَالَ فَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْتُمَا تَطْلُبُ مِيرَاثَكَ مِنْ ابْنِ أَخِيكَ وَيَطْلُبُ هَذَا مِيرَاثَ امْرَأَتِهِ مِنْ أَبِيهَا فَقَالَ أَبُو بَكْرٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نُورَثُ مَا تَرَكْنَاهُ صَدَقَةٌ فَرَأَيْتُمَاهُ كَاذِبًا آثِمًا غَادِرًا خَائِنًا وَاللَّهُ يَعْلَمُ إِنَّهُ لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تُوُفِّيَ أَبُو بَكْرٍ وَأَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَلِيُّ أَبِي بَكْرٍ فَرَأَيْتُمَانِي كَاذِبًا آثِمًا غَادِرًا خَائِنًا وَاللَّهُ يَعْلَمُ إِنِّي لَصَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ فَوَلِيتُهَا ثُمَّ جِئْتَنِي أَنْتَ وَهَذَا وَأَنْتُمَا جَمِيعٌ وَأَمْرُكُمَا وَاحِدٌ فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا فَقُلْتُ إِنْ شِئْتُمْ دَفَعْتُهَا إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ أَنْ تَعْمَلَا فِيهَا بِالَّذِي كَانَ يَعْمَلُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذْتُمَاهَا بِذَلِكَ قَالَ أَكَذَلِكَ قَالَا نَعَمْ قَالَ ثُمَّ جِئْتُمَانِي لِأَقْضِيَ بَيْنَكُمَا وَلَا وَاللَّهِ لَا أَقْضِي بَيْنَكُمَا بِغَيْرِ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهَا فَرُدَّاهَا إِلَيَّحَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَالَ أَرْسَلَ إِلَيَّ عُمَرُ بْنُ الْخَطَّابِ فَقَالَ إِنَّهُ قَدْ حَضَرَ أَهْلُ أَبْيَاتٍ مِنْ قَوْمِكَ بِنَحْوِ حَدِيثِ مَالِكٍ غَيْرَ أَنَّ فِيهِ فَكَانَ يُنْفِقُ عَلَى أَهْلِهِ مِنْهُ سَنَةً وَرُبَّمَا قَالَ مَعْمَرٌ يَحْبِسُ قُوتَ أَهْلِهِ مِنْهُ سَنَةً ثُمَّ يَجْعَلُ مَا بَقِيَ مِنْهُ مَجْعَلَ مَالِ اللَّهِ عَزَّ وَجَلَّ","trj":"Dan telah menceritakan kepadaku [Abdullah bin Muhammad bin Asma Adl dluba'i] telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [Az Zuhri] bahwa [Malik bin Aus] telah menceritakan kepadanya, katanya, \" [Umar bin Khattab] mengundangku, lalu aku datang kepadanya ketika hari mulai panas.\" Malik bin Aus berkata, \"Aku menemukan dia di rumahnya sedang duduk di atas ranjang yang langsung menyentuh tanah, dan bertelekan di atas bantas yang terbuat dari kulit.\" Dia berkata kepadaku, \"Wahai Malik, sesungguhnya kaummu bersama keluarganya telah datang dengan perjalanan yang sangat cepat. Dan aku telah memerintahkan untuk membagikan sesuatu kepada mereka, oleh karena itu bagikanlah (harta rampasan) kepada mereka.\" Malik bin Aus berkata, \"Aku berkata, \"Lebih baik anda memerintahkan orang lain selainku.\" Umar berkata, \"Ambillah wahai Malik.\" Malik bin Aus berkata, \"Lalu datanglah Yarfa seraya berkata, \"Wahai Amirul Mukminin, apakah [Utsman bin 'Affan], [Abdurrahman bin 'Auf], [Zubair bin 'Awwam] dan [Sa'd] boleh masuk?\" Umar menjawab, \"Ya, persilahkanlah mereka masuk.\" Kemudian mereka masuk, setelah itu Yarfa datang lagi saraya berkata, \"Apakah [Ali] dan [Abbas] boleh masuk?\" Umar menjawab, \"Ya, boleh.\" Keduanya pun diizinkan masuk. Lalu Abbas berkata, \"Wahai Amirul Mukminin, berilah keputusan hukum antara aku dengan pendusta, pengkhianat dan pendosa ini.\" Maka sebagian kaum berkata, \"Benar wahai Amirul Mukminin, berilah keputusan terhadapnya dan selesaikanlah urusannya.\" Malik bin Aus berkata, \"Aku berperasangka bahwa Abbas dan Ali yang menggiring rombongan terebut datang.\" Umar berkata, \"Tenanglah kalian berdua, aku memohon kebaikan untuk kalian kepada Allah yang atas izin-Nya berdiri langit dan bumi, apakah kalian tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi sesuatu pun, dan yang kami tinggalkan hanya berupa sedekah.\" Mereka menjawab, \"Benar.\" Kemudian Umar menghadap kepada Ali dan Abbas seraya berkata, \"Aku memohon kebaikan untuk kalian kepada Allah yang atas izin-Nya berdiri langit dan bumi, apakah kalian tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kami tidak mewarisi sesuatu pun, dan yang kami tinggalkan hanya berupa sedekah.\" Abbas dan Ali berkata, \"Ya, benar.\" Umar lantas berkata, \"Sesungguhnya Allah Azza Wa Jalla memberikan kekhususan kepada Rasul-Nya shallallahu 'alaihi wasallam yang tidak diberikan kepada orang lain, Allah berfirman: '(Dan apa saja harta rampasan yang diberikan Allah kepada Rasul-Nya maka harta tersebut untuk Allah dan rasul-Nya …) ' (Qs. Al Hasyr: 7) -aku tidak tahu apakah Umar membaca ayat sebelumnya ataukah tidak-, Umar berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam membagi harta Bani Nadlir kepada kalian. Demi Allah, beliau tidak membuat pemberian itu untuk dirinya sendiri tanpa kalian, sehingga harta itu masih tersisa. Rasulullah shallallahu 'alaihi wasallam mengambil harta tersebut untuk menafkahi keluarganya selama setahun, dan selebihnya beliau menjadikan sebagai harta untuk kemaslahatan umum.\" Kemudian Umar berkata, \"Aku bertanya kepada kalian semua dengan izin Allah yang atas izin-Nya langit dan bumi berdiri, apakah kalian telah mengetahui hal itu?\" mereka menjawab, \"Ya, benar.\" Kemudian dia menghadap ke arah Abbas dan Ali sebagaimana perkataannya kepada rombongan kaum tersebut, \"Apakah kalian berdua mengetahui hal itu?\" keduanya menjawab, \"Ya, benar.\" Umar melanjutkan, \"Ketika Rasulullah shallallahu 'alaihi wasallam wafat, [Abu Bakar] berkata, \"Aku adalah pengganti Rasulullah shallallahu 'alaihi wasallam, kemudian masing-masing dari kalian berdua meminta harta peninggalannya dari anak pamanmu sedangkan yang ini (Ali) menuntut warisan isterinya dari ayahnya, maka Abu Bakar berkata, \"Bukankah Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Kami tidak mewarisi sesuatu apapun, namun yang kami tinggalkan hanyalah berupa sedekah.\" Apakah kalian berdua melihatnya ia seorang pendusta, pendosa dan seorang pengkhianat! Demi Allah, Dia tahu bahwa Abu Bakar adalah orang yang jujur, baik, berakal dan patuh terhadap kebenaran, setelah Abu Bakar wafat, maka akulah pengganti Rasulullah shallallahu 'alaihi wasallam dan pengganti Abu Bakar, maka apakah kalian berdua melihatku seorang pendusta, pendosa dan seorang pengkhianat! Demi Allah, Dia lebih tahu bahwa aku adalah orang yang jujur, baik dan berakal serta mengikuti kebenaran, namun kalian berdua berpaling dariku. Kemudian datang kepadaku, kamu berdua dan ini dan semuanya datang sedangkan perkara kalian hanya satu. Kalian berdua bertanya kepadaku, lalu aku menjawab, \"Jika kalian ingin bagian tersebut aku bagikan kepada kalian, maka kalian harus menggunakannya sesuai dengan yang telah dilakukan Rasulullah shallallahu 'alaihi wasallam, dan kalian mengambil bagian itu sesuai dengan perjanjian yang ada. Tetapi, sekarang kalian datang kepadaku agar aku memberikan keputusan di antara kalian berdua dengan keputusan yang tidak sesuai dengan perjanjian itu. Demi Allah, aku tidak akan memberikan keputusan selain sesuai dengan perjanjian tersebut hingga hari Kiamat. Jika kalian tidak mampu memenuhi persyaratan itu, maka kembalikanlah bagian itu kepadaku.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin rafi'] dan [Abd bin Humaid], [Ibnu Rafi'] berkata; telah menceritakan kepada kami, sedangkan yang dua mengatakan; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Malik bin Aus bin Al Haddatsan] dia berkata, \"Umar bin Khattab mengutus kepadaku seraya berkata, \"Sesungguhnya orang-orang dari beberapa keluarga dari kaummu …seperti hadits Malik, namun dalam haditsnya disebutkan, \"Dengannya beliau menafkahi keluarganya selama setahun.\" Dan sepertinya Ma'mar mengatakan, \"Beliau memberikan nafkah darinya kepada keluarganya selama setahun, kemudian beliau menjadikan sisa dari harta tersebut sebagai harta Allah Azza Wa Jalla.\""},{"p":"Muslim","n":3661,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ وَاللَّفْظُ لِإِسْحَقَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالنَّامِصَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ قَالَ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ وَكَانَتْ تَقْرَأُ الْقُرْآنَ فَأَتَتْهُ فَقَالَتْ مَا حَدِيثٌ بَلَغَنِي عَنْكَ أَنَّكَ لَعَنْتَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَقَالَ عَبْدُ اللَّهِ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ فَقَالَتْ الْمَرْأَةُ لَقَدْ قَرَأْتُ مَا بَيْنَ لَوْحَيْ الْمُصْحَفِ فَمَا وَجَدْتُهُ فَقَالَ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }فَقَالَتْ الْمَرْأَةُ فَإِنِّي أَرَى شَيْئًا مِنْ هَذَا عَلَى امْرَأَتِكَ الْآنَ قَالَ اذْهَبِي فَانْظُرِي قَالَ فَدَخَلَتْ عَلَى امْرَأَةِ عَبْدِ اللَّهِ فَلَمْ تَرَ شَيْئًا فَجَاءَتْ إِلَيْهِ فَقَالَتْ مَا رَأَيْتُ شَيْئًا فَقَالَ أَمَا لَوْ كَانَ ذَلِكَ لَمْ نُجَامِعْهَاحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ وَهُوَ ابْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا مُفَضَّلٌ وَهُوَ ابْنُ مُهَلْهِلٍ كِلَاهُمَا عَنْ مَنْصُورٍ فِي هَذَا الْإِسْنَادِ بِمَعْنَى حَدِيثِ جَرِيرٍ غَيْرَ أَنَّ فِي حَدِيثِ سُفْيَانَ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَفِي حَدِيثِ مُفَضَّلٍ الْوَاشِمَاتِ وَالْمَوْشُومَاتِ و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ بِهَذَا الْإِسْنَادِ الْحَدِيثَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُجَرَّدًا عَنْ سَائِرِ الْقِصَّةِ مِنْ ذِكْرِ أُمِّ يَعْقُوبَ و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِهِمْ","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan ['Utsman bin Abu Syaibah]; Dan lafazh ini miliknya Ishaq; Telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] ia berkata; \"Allah telah mengutuk orang-orang yang membuat tato dan orang yang minta dibuatkan tato, orang-orang yang mencabut bulu mata, orang-orang yang minta dicabut bulu matanya, dan orang-orang yang merenggangkan gigi demi kecantikan yang merubah ciptaan Allah.\" Ternyata ucapan 'Abdullah bin Mas'ud itu sampai kepada seorang wanita dari Bani Asad yang biasa dipanggil Ummu Ya'qub yang pada saat itu sedang membaca Al Qur'an. Kemudian wanita itu datang kepada Ibnu Mas'ud sambil berkata; 'Hai 'Abdullah, apakah benar berita yang sampai kepadaku bahwasanya kamu mengutuk orang-orang yang minta dicabut bulu mata wajahnya dan orang yang merenggangkan giginya demi kecantikan dan merubah ciptaan Allah? ' Abdullah bin Mas'ud menjawab; 'Bagaimana aku tidak akan mengutuk orang-orang yang dikutuk oleh Rasulullah shallallahu 'alaihi wasallam, sedangkan hal itu ada dalam Al Qur'an? ' Wanita itu membantah; 'Aku sudah membaca semua ayat yang ada di antara sampul mushaf, tetapi aku tidak menemukannya.' Ibnu Mas'ud; 'Apabila kamu benar-benar membacanya, niscaya kamu pasti akan menemukannya. Allah subhanahu wata'ala telah berfirman dalam Al Qur'an: 'Apa yang disampaikan Rasul kepadamu terimalah dan apa yang dilarang untukmu tinggalkanlah.' (Qs. Al Hasyr (59): 7). Wanita itu berkata; 'Aku melihat apa yang kamu bicarakan ada pada istrimu sekarang.' Ibnu Mas'ud menjawab; 'Pergi dan lihatlah ia sekarang! ' Lalu wanita itu pergi ke rumah 'Abdullah bin Mas'ud untuk menemui istrinya. Namun, ia tidak melihat sesuatu pun pada dirinya. Akhirnya ia pergi menemui Ibnu Mas'ud dan berkata; 'Benar, aku memang tidak melihat sesuatu pun pada diri istrimu.' Ibnu Mas'ud pun berkata; 'Ketahuilah, jika ia melakukan hal apa yang aku katakan itu, tentunya aku tidak akan menggaulinya lagi.' Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] keduanya; Telah menceritakan kepada kami ['Abdur Rahman] yaitu Ibnu Mahdi; Telah menceritakan kepada kami [Sufyan]; Demikian juga telah diriwayatkan dari jalur yang lain; Dan telah menceritakan kepada kami [Muhammad bin Rafi']; Telah menceritakan kepada kami [Yahya bin Adam]; Telah menceritakan kepada kami [Mufadhdhal] yaitu Ibnu Muhalhil keduanya dari [Manshur] melalui jalur ini yang semakna dengan Hadits Jarir namun di dalam Hadits Sufyan menggunakan lafazh 'Al Waasyimat wal Mustausyimat. Sedangkan di dalam Hadits Mufadhdhal dengan lafazh; 'Al Wasyimaat wal Mausyumaat. Dan telah menceritakannya kepada kami [Abu Bakr bin Abu Syaibah], [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] mereka berkata; Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Manshur] melalui jalur Hadits ini (kisah yang menyebutkan Ummu Ya'qub semuanya) dari Nabi shallallahu 'alaihi wasallam semata. Dan telah menceritakan kepada kami [Syaiban bin Farukh] Telah menceritakan kepada kami [Jarir] yaitu Ibnu Hazm Telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Qamah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam dengan Hadits yang serupa."},{"p":"Muslim","n":4927,"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُطِيعٍ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقُلْتُ لِابْنِ عَبَّاسٍ سُورَةُ التَّوْبَةِ قَالَ آلتَّوْبَةِ قَالَ بَلْ هِيَ الْفَاضِحَةُ مَا زَالَتْ تَنْزِلُ وَمِنْهُمْ وَمِنْهُمْ حَتَّى ظَنُّوا أَنْ لَا يَبْقَى مِنَّا أَحَدٌ إِلَّا ذُكِرَ فِيهَا قَالَ قُلْتُ سُورَةُ الْأَنْفَالِ قَالَ تِلْكَ سُورَةُ بَدْرٍ قَالَ قُلْتُ فَالْحَشْرُ قَالَ نَزَلَتْ فِي بَنِي النَّضِيرِ","trj":"Telah menceritakan kepadaku [Abdullah bin Muthi'] telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] berkata: Saya berkata kepada [Ibnu 'Abbas]: Surat At Taubah, ia berkata: Apa At Taubah? Ia berkata: Bahkan ia adalah Al Fadhilah (yang menyibak rahasia orang-orang munafik, pent.) yang masih turun dan dari mereka dan dari mereka hingga mereka mengira tiada seorangpun dari kita yang masih tersisa kecuali telah disebutkan di dalamnya. Ia berkata: Aku berkata: Surat Al Anfaal, ia (Ibnu Abbas) berkata: Itu adalah surat perang Badar. Ia berkata: Lalu aku berkata: Surat Al Hasyr, ia (Ibnu Abbas) berkata: Ia turun berkenaan dengan Bani Nadhir."},{"p":"Nasa'i","n":5278,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ حَيَّانَ سَمِعَ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ أَنَّهُ سَمِعَ ابْنَ عُمَرَ وَابْنَ عَبَّاسٍأَنَّهُمَا شَهِدَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ ثُمَّ تَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الْآيَةَ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }","trj":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] ia berkata; telah menceritakan kepada kami [Yazid bin Harun] ia berkata; telah menceritakan kepada kami [Manshur bin Hayyan] ia mendengar [Sa'id bin Jubair] menceritakan bahwasanya ia mendengar [Ibnu Umar] dan [Ibnu Abbas] bersaksi atas Rasulullah shallallahu 'alaihi wasallam, bahwa beliau melarang dari Ad Duba, Al Hantam, Al Muzaffat dan An Naqir. Kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat berikut ini: '(Apa yang diberikan Rasul kepadamu maka terimalah dia. Dan apa yang dilarangnya bagimu maka tinggalkanlah..) ' (Qs. Al Hasyr: 7).\" "},{"p":"Nasa'i","n":5279,"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ عَنْ ابْنِ عَمٍّ لَهَا يُقَالُ لَهُ أَنَسٌ قَالَ قَالَ ابْنُ عَبَّاسٍأَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ مَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قُلْتُ بَلَى قَالَ أَلَمْ يَقُلْ اللَّهُ{ وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى اللَّهُ وَرَسُولُهُ أَمْرًا أَنْ يَكُونَ لَهُمْ الْخِيَرَةُ مِنْ أَمْرِهِمْ }قُلْتُ بَلَى قَالَ فَإِنِّي أَشْهَدُ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّقِيرِ وَالْمُقَيَّرِ وَالدُّبَّاءِ وَالْحَنْتَمِ","trj":"Telah mengabarkan kepada kami [Suwaid] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Sulaiman At Taimi] dari [Asma binti Yazid] dari anak pamannya yang dipanggil [Anas] ia berkata; [Ibnu Abbas] berkata, \"Bukankah Allah telah mengatakan: '(Apa yang diberikan Rasul kepadamu maka terimalah dia. Dan apa yang dilarangnya bagimu maka tinggalkanlah..) '? (Qs. Al Hasyr: 7), aku menjawab, \"Benar.\" Ibnu Abbas berkata lagi, \"Bukankah Allah telah mengatakan: '(Dan tidaklah patut bagi laki-laki yang Mukmin dan tidak (pula) bagi perempuan yang Mukmin, apabila Allah dan Rasul-Nya telah menetapkan suatu ketetapan, akan ada bagi mereka pilihan (yang lain) tentang urusan mereka..)? (Qs. Al Hasyr: 36), aku menjawab, \"Benar.\" Ibnu Abbas lantas berkata, \"Sesungguhnya aku bersaksi bahwa Nabi Allah shallallahu 'alaihi wasallam melarang An Naqir, Al Muqayyar, Ad Duba dan Al Hantam.\" "},{"p":"Tirmidzi","n":1472,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذَهَبَ قَوْمٌ مِنْ أَهْلِ الْعِلْمِ إِلَى هَذَا وَلَمْ يَرَوْا بَأْسًا بِقَطْعِ الْأَشْجَارِ وَتَخْرِيبِ الْحُصُونِ وَكَرِهَ بَعْضُهُمْ ذَلِكَ وَهُوَ قَوْلُ الْأَوْزَاعِيِّ قَالَ الْأَوْزَاعِيُّ وَنَهَى أَبُو بَكْرٍ الصِّدِّيقُ أَنْ يَقْطَعَ شَجَرًا مُثْمِرًا أَوْ يُخَرِّبَ عَامِرًا وَعَمِلَ بِذَلِكَ الْمُسْلِمُونَ بَعْدَهُ و قَالَ الشَّافِعِيُّ لَا بَأْسَ بِالتَّحْرِيقِ فِي أَرْضِ الْعَدُوِّ وَقَطْعِ الْأَشْجَارِ وَالثِّمَارِ و قَالَ أَحْمَدُ وَقَدْ تَكُونُ فِي مَوَاضِعَ لَا يَجِدُونَ مِنْهُ بُدًّا فَأَمَّا بِالْعَبَثِ فَلَا تُحَرَّقْ و قَالَ إِسْحَقُ التَّحْرِيقُ سُنَّةٌ إِذَا كَانَ أَنْكَى فِيهِمْ","trj":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] berkata, \"bahwasanya Rasulullah shallallahu 'alaihi wasallam menebang dan membakar kebun kurma milik bani Nadhir, tepatnya di wilayah Buwairah. Maka Allah menurunkan ayat-Nya: '(Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya, maka (semua itu) adalah dengan izin Allah; dan karena Dia hendak memberikan kehinaan kepada orang-orang fasik) ' -Qs. Al Hasyr: 5-Dalam bab ini ada hadits serupa dari Ibnu Abbas. Hadits ini derajatnya hasan shahih. sebagian ulama` berpegangan dengan hadits ini, dan mereka tidak mempermasalahkan atas pembolehan menebang pohon kurma dan menghancurkan benteng. Namun sebagian yang lain memakruhkan hal tersebut, dan ini adalah pendapat Al Auza'i. Al Auza'I berkata, \"Abu Bakar Ash Shiddiq telah melarang menebang pohon yang sedang berbuah atau menghancurkan bangunan, dan kaum muslimin setelahnya juga melakukan sebagaimana yang dilakukan oleh Abu Bakar Ash Shiddiq.\" Imam Syafi'I berkata, \"Tidak apa-apa membakar dan menebang pohon yang berbuah di wilayah musuh.\" Imam Ahmad berkata, \"Untuk beberapa kasus tidak apa-apa melakukan hal itu, tetapi jika itu menimbulkan kesia-siaan maka tidak boleh membakar.\" Sementara Ishaq mengatakan, \"Jika membakar itu bisa membuat kerugian dipihak musuh maka itu sunah.\""},{"p":"Tirmidzi","n":2777,"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا خَالِدُ بْنُ طَهْمَانَ أَبُو الْعَلَاءِ الْخَفَّافُ حَدَّثَنِي نَافِعُ بْنُ أَبِي نَافِعٍ عَنْ مَعْقِلِ بْنِ يَسَارٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ حِينَ يُصْبِحُ ثَلَاثَ مَرَّاتٍ أَعُوذُ بِاللَّهِ السَّمِيعِ الْعَلِيمِ مِنْ الشَّيْطَانِ الرَّجِيمِ وَقَرَأَ ثَلَاثَ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَكَّلَ اللَّهُ بِهِ سَبْعِينَ أَلْفَ مَلَكٍ يُصَلُّونَ عَلَيْهِ حَتَّى يُمْسِيَ وَإِنْ مَاتَ فِي ذَلِكَ الْيَوْمِ مَاتَ شَهِيدًا وَمَنْ قَالَهَا حِينَ يُمْسِي كَانَ بِتِلْكَ الْمَنْزِلَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","trj":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Khalid bin Thaman Abu Al Ala` Al Khaffaf] telah menceritakan kepadaku [Nafi' bin Abu Nafi'] dari [Ma'qil bin Yasar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membaca tiga kali di pagi hari, A'UUDZU BILLAAHI MINASY SYAITHAANIR RAJIIM kemudian membaca tiga ayat terakhir surat Al Hasyr, maka dengannya Allah akan menugaskan tujuhpuluh ribu malikat untuk mendoakannya hingga sore hari dan bila ia meninggal pada hari itu, ia mati dalam keadaan syahid dan barangsiapa mengucapkannya di sore hati, kedudukannya sama seperti itu.\" Abu Isa berkata; Hadits ini gharib, kami hanya mengetahuinya melalui sanad ini."},{"p":"Tirmidzi","n":3053,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَحَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَخْلَ بَنِي النَّضِيرِ وَقَطَّعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar radliallahu 'anhuma], ia berkata; Rasulullah shallallahu 'alaihi wasallam membakar pohon kurma Bani An Nazhir, dan menebanginya dan pohon tersebut ada di Al Buwairah. Kemudian Allah menurunkan ayat: \"Apa saja yang kamu tebang dari pohon kurma (milik orang-orang kafir) atau yang kamu biarkan (tumbuh) berdiri di atas pokoknya, maka (semua itu) adalah dengan izin Allah; dan karena Dia hendak memberikan kehinaan kepada orang-orang fasik.\" (QS. Alhasyr 5), Abu Isa berkata; hadits ini adalah hadits hasan shahih."},{"p":"Tirmidzi","n":3055,"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ فُضَيْلِ بْنِ غَزْوَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا مِنْ الْأَنْصَارِ بَاتَ بِهِ ضَيْفٌ فَلَمْ يَكُنْ عِنْدَهُ إِلَّا قُوتُهُ وَقُوتُ صِبْيَانِهِ فَقَالَ لِامْرَأَتِهِ نَوِّمِي الصِّبْيَةَ وَأَطْفِئِي السِّرَاجَ وَقَرِّبِي لِلضَّيْفِ مَا عِنْدَكِ فَنَزَلَتْ هَذِهِ الْآيَةَ{ وَيُؤْثِرُونَ عَلَى أَنْفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ }هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dari [Fudhail bin Ghazwan] dari [Abu Hazim] dari [Abu Hurairah] bahwa seorang laki-laki dari kalangan anshar bermalam dengan kedatangan seorang tamu sementara ia tidak memiliki makanan kecuali makanan untuk anak-anaknya. Kemudian ia berkata kepada isterinya; tidurkan anak-anak tersebut, dan matikan lampu serta hidangkan apa yang engkau miliki kepada tamu tersebut. Kemudian turunlah ayat ini: \"Dan mereka mengutamakan (orang-orang Muhajirin), atas diri mereka sendiri, sekalipun mereka dalam kesusahan.\" (QS. Alhasyr ayat 9), hadits ini adalah hadits hasan shahih."}]};
